const WORDS_ADDITIONS = [
{ en:"Coronary artery anatomy", de:"Koronararterienanatomie", abbr:"", ja:"冠動脈解剖", note:"左主幹部→LAD（前下行枝）・LCX（回旋枝）/ 右冠動脈（RCA）。冠動脈バイパス術の計画に重要。", example:"Coronary artery anatomy was reviewed before planning the bypass graft.", cat:"anatomy", level:"intermediate", dept:"CSURG" },
{ en:"Saphenous vein graft", de:"Venengraft aus der Vena saphena", abbr:"SVG", ja:"伏在静脈グラフト", note:"冠動脈バイパス術に使用する自家静脈。下腿から採取。動脈グラフトより10年開存率が低い。", example:"Three saphenous vein grafts were used for the coronary bypass.", cat:"treatment", level:"intermediate", dept:"CSURG" },
{ en:"Internal mammary artery graft", de:"Arteria-mammaria-interna-Graft", abbr:"IMA", ja:"内胸動脈グラフト", note:"LADへの第一選択バイパスグラフト。10年開存率90%以上。左内胸動脈（LIMA）が最多使用。", example:"Left internal mammary artery was anastomosed to the LAD.", cat:"treatment", level:"intermediate", dept:"CSURG" },
{ en:"Cardiopulmonary bypass time", de:"Herzlungenmaschinenzeit", abbr:"CPB time", ja:"体外循環時間", note:"心臓手術中の体外循環使用時間。長時間になると神経学的合併症・炎症・凝固障害リスクが増加。", example:"Cardiopulmonary bypass time was 95 minutes for the double valve replacement.", cat:"diagnosis", level:"advanced", dept:"CSURG" },
{ en:"Aortic cross clamp time", de:"Aortenklemmenzeit", abbr:"XCT", ja:"大動脈遮断時間", note:"心筋保護液注入後の大動脈遮断時間。30〜90分が目安。延長で心筋障害リスク増大。", example:"Aortic cross clamp time was kept under 60 minutes.", cat:"diagnosis", level:"advanced", dept:"CSURG" },
{ en:"Myocardial protection", de:"Myokardprotektion", abbr:"", ja:"心筋保護", note:"体外循環中の心停止中の心筋保護。冷温心停止液（カリウム含有）を冠動脈に注入。", example:"Antegrade myocardial protection was achieved with cold crystalloid cardioplegia.", cat:"treatment", level:"advanced", dept:"CSURG" },
{ en:"Aortic valve area", de:"Aortenklappenfläche", abbr:"AVA", ja:"大動脈弁口面積", note:"正常>2.0cm²。<1.0cm²で重症狭窄。Gorlin式またはエコーで計算。手術適応の判断基準。", example:"Aortic valve area was 0.7 cm², meeting criteria for severe aortic stenosis.", cat:"diagnosis", level:"intermediate", dept:"CSURG" },
{ en:"Mitral regurgitation grading", de:"Mitralinsuffizienzgrad", abbr:"MR grade", ja:"僧帽弁逆流の重症度分類", note:"I〜IVの4段階。エコーで評価。III〜IVで症状・EF低下があれば手術適応。", example:"Mitral regurgitation was graded as IV, indicating severe regurgitation.", cat:"diagnosis", level:"intermediate", dept:"CSURG" },
{ en:"Prosthetic valve", de:"Herzklappenprothese", abbr:"", ja:"人工弁", note:"機械弁（永続的抗凝固必要）/ 生体弁（抗凝固不要・耐久性10〜20年）。年齢・ライフスタイルで選択。", example:"A bioprosthetic valve was chosen for the 72-year-old patient.", cat:"treatment", level:"intermediate", dept:"CSURG" },
{ en:"Valve-in-valve procedure", de:"Valve-in-valve-Eingriff", abbr:"ViV", ja:"バルブインバルブ手技", note:"劣化した生体弁に経カテーテルで新しい弁を留置する低侵襲再手術。高齢・高リスク患者に適応。", example:"A valve-in-valve TAVI was performed for the degenerated bioprosthetic aortic valve.", cat:"treatment", level:"advanced", dept:"CSURG" },
{ en:"Ventricular assist device", de:"Ventrikuläres Unterstützungssystem", abbr:"VAD", ja:"補助人工心臓", note:"心室の機能を補助するポンプ。LVAD・RVAD・BiVADがある。移植橋渡し・長期補助として使用。", example:"LVAD implantation was planned as a bridge to heart transplantation.", cat:"treatment", level:"advanced", dept:"CSURG" },
{ en:"Sternotomy", de:"Sternotomie", abbr:"", ja:"胸骨正中切開", note:"心臓手術の標準アプローチ。胸骨を縦に切開。閉鎖はステンレスワイヤーで固定。術後疼痛・呼吸制限に注意。", example:"Median sternotomy provided excellent exposure for the cardiac surgery.", cat:"treatment", level:"intermediate", dept:"CSURG" },
{ en:"Sternal wound infection", de:"Sternale Wundinfektion", abbr:"SWI", ja:"胸骨創感染", note:"開心術後の重篤な合併症。表在性〜縦隔炎（深部感染）に分類。デブリードマン・筋弁再建が治療。", example:"Deep sternal wound infection required debridement and pectoralis muscle flap closure.", cat:"diagnosis", level:"advanced", dept:"CSURG" },
{ en:"Postpericardiotomy syndrome", de:"Postperikardiotomiesyndrom", abbr:"", ja:"心膜切開後症候群", note:"開心術後1〜6週に発症する発熱・胸痛・心膜炎。自己免疫機序。NSAIDs・コルヒチンで治療。", example:"Postpericardiotomy syndrome was treated with ibuprofen and colchicine.", cat:"diagnosis", level:"intermediate", dept:"CSURG" },
{ en:"Atrial fibrillation after cardiac surgery", de:"Postoperatives Vorhofflimmern", abbr:"POAF", ja:"術後心房細動", note:"開心術後30〜50%に発生。術後2〜3日目に多い。β遮断薬・アミオダロン・電気的除細動で対処。", example:"Postoperative atrial fibrillation was rate-controlled with metoprolol.", cat:"diagnosis", level:"intermediate", dept:"CSURG" },
{ en:"Extracorporeal membrane oxygenation", de:"Extrakorporale Membranoxygenierung", abbr:"ECMO", ja:"体外式膜型人工肺（ECMO）", note:"重症心肺不全への体外循環補助。VA-ECMO（心肺）/ VV-ECMO（肺のみ）。心臓移植・回復の橋渡し。", example:"VA-ECMO was initiated for the refractory cardiogenic shock.", cat:"treatment", level:"advanced", dept:"CSURG" },
{ en:"Pump failure", de:"Pumpversagen", abbr:"", ja:"低心拍出量症候群（ポンプ不全）", note:"開心術後の心機能低下。強心薬・IABP・VADで対処。原因を評価（心筋保護不足・再灌流障害）。", example:"Pump failure after surgery required inotropic support and IABP insertion.", cat:"diagnosis", level:"advanced", dept:"CSURG" },
{ en:"Reoperation cardiac surgery", de:"Reoperative Herzchirurgie", abbr:"redo surgery", ja:"再手術（開心術）", note:"前回手術後の心臓再手術。癒着・出血リスクが高い。オルタナティブアプローチ・体外循環準備が重要。", example:"Redo sternotomy was required for the degenerated bioprosthetic valve.", cat:"treatment", level:"advanced", dept:"CSURG" },
{ en:"Wound classification", de:"Wundklassifikation", abbr:"", ja:"創傷分類", note:"清潔（Class I）/ 清潔汚染（II）/ 汚染（III）/ 不潔（IV）。感染リスク・抗菌薬投与の指標。", example:"The wound was classified as contaminated class III, requiring antibiotic prophylaxis.", cat:"diagnosis", level:"intermediate", dept:"PSURG" },
{ en:"Reconstructive ladder", de:"Rekonstruktionsleiter", abbr:"", ja:"再建の梯子（ラダー）", note:"創傷再建の原則。一次閉鎖→二次治癒→植皮→局所皮弁→遊離皮弁の順に複雑度が増す。", example:"The reconstructive ladder guided the decision to use a local flap for the defect.", cat:"common", level:"intermediate", dept:"PSURG" },
{ en:"Split thickness skin graft", de:"Spalthautransplantat", abbr:"STSG", ja:"分層植皮術", note:"表皮＋真皮の一部を採取。採皮部は再生する。広い創・熱傷後の被覆に使用。ドナーサイト痛が問題。", example:"A split thickness skin graft from the thigh was used to cover the burn wound.", cat:"treatment", level:"intermediate", dept:"PSURG" },
{ en:"Pedicle flap", de:"Gestielter Lappen", abbr:"", ja:"有茎皮弁", note:"血管茎を保ったまま移動する皮弁。ランダム・軸型に分類。遊離皮弁より安全だが移動距離に制限。", example:"A pedicle flap was rotated to cover the sacral pressure ulcer.", cat:"treatment", level:"intermediate", dept:"PSURG" },
{ en:"Free flap", de:"Freier Lappen", abbr:"", ja:"遊離皮弁", note:"血管茎を切離し遠隔部位に移植する皮弁。マイクロサージャリーで血管吻合。広範囲欠損・再建に使用。", example:"A free anterolateral thigh flap was used for the mandibular reconstruction.", cat:"treatment", level:"advanced", dept:"PSURG" },
{ en:"Skin graft take", de:"Einheilung des Hauttransplantats", abbr:"", ja:"植皮生着", note:"植皮が移植部位に生着すること。不動化・感染予防が重要。色・質感・生着率で評価。", example:"Skin graft take was 95%, indicating excellent healing.", cat:"diagnosis", level:"intermediate", dept:"PSURG" },
{ en:"Negative pressure wound therapy", de:"Unterdruckwundtherapie", abbr:"NPWT", ja:"陰圧閉鎖療法（VAC療法）", note:"創部に陰圧をかけて肉芽形成促進・滲出液除去。慢性創傷・術後創・複雑創傷に使用。", example:"Negative pressure wound therapy accelerated healing of the diabetic foot ulcer.", cat:"treatment", level:"intermediate", dept:"PSURG" },
{ en:"Hypertrophic scar", de:"Hypertrophe Narbe", abbr:"", ja:"肥厚性瘢痕", note:"傷跡の範囲内で過剰増殖した線維性瘢痕。ケロイドと異なり境界を超えない。自然退縮あり。", example:"Hypertrophic scar after the burn was managed with compression garments.", cat:"diagnosis", level:"basic", dept:"PSURG" },
{ en:"Diabetic foot ulcer", de:"Diabetisches Fußgeschwür", abbr:"DFU", ja:"糖尿病性足潰瘍", note:"神経障害＋末梢動脈疾患による難治性足部潰瘍。感染・壊疽→切断リスク。多職種チームで管理。", example:"Diabetic foot ulcer was managed with debridement, offloading, and vascular assessment.", cat:"diagnosis", level:"intermediate", dept:"PSURG" },
{ en:"Lymphedema", de:"Lymphödem", abbr:"", ja:"リンパ浮腫", note:"リンパ管の障害による組織間液貯留。原発性（先天）/ 二次性（癌手術・放射線・感染後）。圧迫療法が主体。", example:"Lymphedema of the arm developed after axillary lymph node dissection.", cat:"diagnosis", level:"intermediate", dept:"PSURG" },
{ en:"Intracranial hypertension", de:"Intrakranielle Hypertension", abbr:"ICH", ja:"頭蓋内圧亢進", note:"ICP>20mmHg。頭痛・嘔吐・乳頭浮腫の三徴。脳ヘルニアを予防するための緊急治療が必要。", example:"Intracranial hypertension was managed with head elevation, osmotherapy, and sedation.", cat:"diagnosis", level:"intermediate", dept:"NSURG" },
{ en:"Cerebral perfusion pressure", de:"Zerebraler Perfusionsdruck", abbr:"CPP", ja:"脳灌流圧", note:"CPP = MAP - ICP。60〜70mmHgを維持することが目標。低下で脳虚血リスク増大。", example:"Cerebral perfusion pressure was maintained above 60 mmHg with vasopressors.", cat:"diagnosis", level:"advanced", dept:"NSURG" },
{ en:"Osmotherapy", de:"Osmotherapie", abbr:"", ja:"浸透圧療法", note:"高頭蓋内圧の治療。マンニトール（0.25〜1g/kg）/ 高張食塩水（3%）で血漿浸透圧を上昇させ脳浮腫を軽減。", example:"Osmotherapy with mannitol was given for the acute elevation in ICP.", cat:"treatment", level:"intermediate", dept:"NSURG" },
{ en:"External ventricular drain", de:"Externe Ventrikeldrainage", abbr:"EVD", ja:"脳室外ドレナージ", note:"脳室内にカテーテルを留置してCSFを排液。ICP測定・水頭症・SAH後の脳室内出血管理に使用。", example:"An external ventricular drain was placed to control ICP after the subarachnoid hemorrhage.", cat:"treatment", level:"intermediate", dept:"NSURG" },
{ en:"Cerebral vasospasm", de:"Zerebraler Vasospasmus", abbr:"", ja:"脳血管攣縮", note:"SAH後4〜14日に発症する脳動脈の攣縮。遅発性虚血の原因。Triple H療法・ニカルジピン動注で治療。", example:"Cerebral vasospasm was detected by TCD and treated with induced hypertension.", cat:"diagnosis", level:"advanced", dept:"NSURG" },
{ en:"Transcranial Doppler", de:"Transkranielle Dopplersonografie", abbr:"TCD", ja:"経頭蓋ドプラ法", note:"頭蓋骨を通した脳血流速度測定。脳血管攣縮・脳死・自動調節能の評価に使用。", example:"TCD showed elevated flow velocities in the MCA, indicating vasospasm.", cat:"diagnosis", level:"advanced", dept:"NSURG" },
{ en:"Spinal cord injury level", de:"Rückenmarksverletzungsniveau", abbr:"SCI level", ja:"脊髄損傷レベル", note:"ASIA分類（A〜E）で機能評価。C3〜4以上で呼吸筋麻痺・人工呼吸器必要。早期リハビリが重要。", example:"Spinal cord injury at C5 resulted in tetraplegia with preserved shoulder function.", cat:"diagnosis", level:"intermediate", dept:"NSURG" },
{ en:"ASIA impairment scale", de:"ASIA-Beeinträchtigungsskala", abbr:"AIS", ja:"ASIA機能障害分類", note:"A（完全）/ B（感覚のみ保存）/ C（運動保存・筋力3未満）/ D（運動保存・筋力3以上）/ E（正常）。", example:"ASIA grade C indicated incomplete spinal cord injury with some motor function preserved.", cat:"diagnosis", level:"intermediate", dept:"NSURG" },
{ en:"Disc herniation surgery", de:"Bandscheibenvorfallsoperation", abbr:"", ja:"椎間板ヘルニア手術", note:"保存療法抵抗性・神経障害進行例に手術適応。頸椎（前方除圧固定）/ 腰椎（後方椎間板摘出術）。", example:"Disc herniation surgery was performed for the progressive leg weakness unresponsive to conservative treatment.", cat:"treatment", level:"intermediate", dept:"NSURG" },
{ en:"Epilepsy surgery", de:"Epilepsiechirurgie", abbr:"", ja:"てんかん外科手術", note:"薬剤抵抗性てんかんの外科的治療。側頭葉切除・皮質切除・脳梁離断・迷走神経刺激術など。", example:"Epilepsy surgery was considered after two antiepileptic drugs failed to control seizures.", cat:"treatment", level:"advanced", dept:"NSURG" },
{ en:"Carotid artery stenosis", de:"Karotisstenose", abbr:"", ja:"頸動脈狭窄症", note:"症候性>50%・無症候性>70〜80%で手術（CEAまたはCAS）適応。TIA・脳卒中の原因。", example:"Carotid artery stenosis of 75% was treated with carotid endarterectomy.", cat:"diagnosis", level:"intermediate", dept:"NSURG" },
{ en:"Meningeal irritation signs", de:"Meningismuszeichen", abbr:"", ja:"髄膜刺激徴候", note:"項部硬直・Kernig徴候・Brudzinski徴候の三徴。髄膜炎・SAHで陽性。腰椎穿刺の適応。", example:"Meningeal irritation signs were present, prompting urgent lumbar puncture.", cat:"diagnosis", level:"intermediate", dept:"NSURG" },
{ en:"Ventriculoperitoneal shunt revision", de:"VP-Shunt-Revision", abbr:"VP shunt revision", ja:"VPシャント改定術", note:"シャント機能不全・感染・過剰排液時の再手術。小児・正常圧水頭症患者で頻繁に必要。", example:"VP shunt revision was required for the blocked proximal catheter.", cat:"treatment", level:"intermediate", dept:"NSURG" },
{ en:"Posterior fossa surgery", de:"Hintere Schädelgrubenoperation", abbr:"", ja:"後頭蓋窩手術", note:"小脳・脳幹・第4脳室の手術。腹臥位または側臥位。脳神経・脳幹損傷・気脳症に注意。", example:"Posterior fossa surgery removed the acoustic neuroma via a retrosigmoid approach.", cat:"treatment", level:"advanced", dept:"NSURG" },
{ en:"Preoperative assessment", de:"Präoperative Beurteilung", abbr:"", ja:"術前評価", note:"全身状態・合併症・薬剤・麻酔リスクの評価。ASA分類・心肺機能・栄養状態を確認。", example:"Preoperative assessment revealed poorly controlled diabetes requiring optimization before surgery.", cat:"diagnosis", level:"basic", dept:"SURG" },
{ en:"Surgical consent", de:"Operationseinwilligung", abbr:"", ja:"手術同意書", note:"手術の目的・方法・リスク・代替手段を説明後に取得。患者の自律尊重の基本。緊急時は例外あり。", example:"Informed surgical consent was obtained after a detailed discussion of the risks and benefits.", cat:"common", level:"basic", dept:"SURG" },
{ en:"Laparoscopic surgery", de:"Laparoskopische Chirurgie", abbr:"", ja:"腹腔鏡手術", note:"小切開から内視鏡・器具を挿入して行う低侵襲手術。術後回復が早い・疼痛少・入院期間短縮。", example:"Laparoscopic cholecystectomy was performed for symptomatic gallstones.", cat:"treatment", level:"basic", dept:"SURG" },
{ en:"Robotic surgery", de:"Robotergestützte Chirurgie", abbr:"", ja:"ロボット支援手術", note:"da Vinciなどの手術支援ロボット。精密動作・3D視野・手振れ補正。前立腺・婦人科・大腸手術で普及。", example:"Robotic-assisted prostatectomy offered better visualization and precision than open surgery.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Postoperative ileus", de:"Postoperativer Ileus", abbr:"POI", ja:"術後腸管麻痺（術後イレウス）", note:"術後の腸蠕動停止。嘔気・嘔吐・腹部膨満。早期離床・経口摂取・オピオイド最小化で予防。", example:"Postoperative ileus resolved with conservative management on day 4.", cat:"diagnosis", level:"intermediate", dept:"SURG" },
{ en:"Surgical drain", de:"Operationsdrainage", abbr:"", ja:"術後ドレーン", note:"術後の血液・漿液・胆汁・消化液を体外に誘導。排液量・性状で術後経過を評価。不要時は早期抜去。", example:"Surgical drain output decreased to 20 mL per day, allowing removal on day 5.", cat:"treatment", level:"basic", dept:"SURG" },
{ en:"Evisceration", de:"Eventration", abbr:"", ja:"腸管脱出（エビセレーション）", note:"腸管が腹壁創から脱出した状態。緊急手術適応。湿潤ガーゼで被覆して緊急室へ。", example:"Evisceration after wound dehiscence required emergency surgical repair.", cat:"diagnosis", level:"advanced", dept:"SURG" },
{ en:"Deep vein thrombosis prophylaxis", de:"Thromboseprophylaxe", abbr:"DVT prophylaxis", ja:"深部静脈血栓予防", note:"術後DVT・PE予防。早期離床・弾性ストッキング・低分子ヘパリン・間欠的空気圧迫装置。", example:"DVT prophylaxis was started with LMWH on the day of surgery.", cat:"treatment", level:"basic", dept:"SURG" },
{ en:"Enhanced recovery after surgery", de:"Enhanced Recovery After Surgery", abbr:"ERAS", ja:"術後回復強化プログラム（ERAS）", note:"術前・術中・術後の多モーダルな介入で回復を促進。早期経口摂取・早期離床・疼痛管理最適化。", example:"ERAS protocol reduced hospital stay from 7 to 4 days after colorectal surgery.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Surgical site infection prevention", de:"Prävention von Wundinfektionen", abbr:"SSI prevention", ja:"手術部位感染予防", note:"術前の皮膚消毒・抗菌薬予防投与・体温管理・血糖管理・無菌操作が予防の柱。", example:"SSI prevention bundle reduced infection rates by 40% in the surgical unit.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Blood loss estimation", de:"Blutverlustabschätzung", abbr:"", ja:"出血量の推定", note:"吸引量＋ガーゼ重量法で推定。許容出血量（ABL）= EBV × (Hct初期 - Hct最低) / Hct平均。", example:"Intraoperative blood loss was estimated at 800 mL, requiring transfusion.", cat:"diagnosis", level:"intermediate", dept:"SURG" },
{ en:"Surgical bleeding control", de:"Chirurgische Blutstillung", abbr:"", ja:"術中止血", note:"電気焼灼・結紮・縫合・クリップ・骨蝋・止血剤・タンポナーデなど様々な止血法。", example:"Surgical bleeding was controlled with bipolar electrocautery and hemostatic sutures.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Stoma creation", de:"Stomaanlage", abbr:"", ja:"ストーマ造設", note:"消化管・尿路を腹壁に開口する手術。コロストミー・イレオストミー・ウロストミー。術前サイト選定が重要。", example:"An end colostomy was created after the Hartmann procedure for the perforated sigmoid.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Stoma reversal", de:"Stomarückverlagerung", abbr:"", ja:"ストーマ閉鎖術", note:"一時的ストーマの閉鎖・腸管再吻合術。吻合部の状態確認後に実施。術後腸閉塞・縫合不全に注意。", example:"Stoma reversal was performed 3 months after the initial surgery.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Perioperative fluid management", de:"Perioperatives Flüssigkeitsmanagement", abbr:"", ja:"周術期輸液管理", note:"Goal-directed therapyによる輸液最適化。過剰輸液→浮腫・腸管麻痺。不足→臓器灌流低下。", example:"Goal-directed perioperative fluid management reduced postoperative complications.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Bowel prep", de:"Darmvorbereitung", abbr:"", ja:"腸管前処置（大腸手術前）", note:"大腸手術前の機械的腸管洗浄＋経口抗菌薬。SSI・縫合不全の予防。現在は省略する施設も増加。", example:"Oral bowel prep with polyethylene glycol was given the day before the colon surgery.", cat:"treatment", level:"intermediate", dept:"SURG" },
{ en:"Induction of anesthesia", de:"Anästhesieeinleitung", abbr:"", ja:"麻酔導入", note:"意識消失から挿管・気道確保までの過程。プロポフォール・ケタミン・エトミデートなど使用。", example:"Induction of anesthesia was smooth with propofol and rocuronium for RSI.", cat:"treatment", level:"basic", dept:"ANES" },
{ en:"Maintenance of anesthesia", de:"Anästhesieaufrechterhaltung", abbr:"", ja:"麻酔維持", note:"吸入麻酔薬（セボフルラン・デスフルラン）またはTIVA（プロポフォール持続）で維持。", example:"Anesthesia maintenance was achieved with sevoflurane and remifentanil infusion.", cat:"treatment", level:"intermediate", dept:"ANES" },
{ en:"Bispectral index", de:"Bispektraler Index", abbr:"BIS", ja:"バイスペクトラルインデックス（BIS）", note:"EEGを処理した麻酔深度モニター。0〜100。40〜60が全身麻酔の目標域。術中覚醒の予防に使用。", example:"BIS monitoring was used to prevent intraoperative awareness during the procedure.", cat:"diagnosis", level:"intermediate", dept:"ANES" },
{ en:"Neuromuscular monitoring", de:"Neuromuskuläres Monitoring", abbr:"NMT", ja:"筋弛緩モニタリング", note:"TOF（四連刺激）でTOF比>0.9を確認してから抜管。残存筋弛緩は術後呼吸不全の原因。", example:"Neuromuscular monitoring confirmed complete reversal before extubation.", cat:"diagnosis", level:"intermediate", dept:"ANES" },
{ en:"Sugammadex", de:"Sugammadex", abbr:"", ja:"スガマデクス", note:"ロクロニウム・ベクロニウムの選択的拮抗薬。ネオスチグミンより完全・迅速な拮抗が可能。", example:"Sugammadex 200 mg was given to rapidly reverse the rocuronium block.", cat:"treatment", level:"intermediate", dept:"ANES" },
{ en:"Epidural test dose", de:"Epiduraler Testbolus", abbr:"", ja:"硬膜外テスト投与", note:"硬膜外カテーテルの血管内誤挿入・くも膜下誤挿入を確認。リドカイン＋エピネフリン3mLを投与。", example:"Epidural test dose showed no signs of intravascular or intrathecal injection.", cat:"treatment", level:"intermediate", dept:"ANES" },
{ en:"Spinal headache", de:"Spinalkopfschmerz", abbr:"PDPH", ja:"硬膜穿刺後頭痛", note:"Post-Dural Puncture Headache。脊椎麻酔・腰椎穿刺後。起立性頭痛。硬膜外血液パッチが最も有効。", example:"Spinal headache after lumbar puncture was treated with an epidural blood patch.", cat:"diagnosis", level:"intermediate", dept:"ANES" },
{ en:"Hypotension during anesthesia", de:"Hypotonie unter Anästhesie", abbr:"", ja:"麻酔中低血圧", note:"脊椎麻酔後・血管拡張薬・出血が原因。エフェドリン・フェニレフリン・輸液で対処。胎児への影響に注意。", example:"Hypotension during spinal anesthesia was treated with phenylephrine infusion.", cat:"diagnosis", level:"intermediate", dept:"ANES" },
{ en:"Airway fire", de:"Atemwegsbrand", abbr:"", ja:"気道火災", note:"レーザー手術中のETT・気道分泌物の着火。酸素濃度を下げる・生食スポンジで消火・挿管し直す。", example:"Airway fire was prevented by using laser-safe ETT and minimizing FiO2 during the procedure.", cat:"diagnosis", level:"advanced", dept:"ANES" },
{ en:"Obese patient anesthesia", de:"Anästhesie bei adipösen Patienten", abbr:"", ja:"肥満患者の麻酔管理", note:"困難気道・換気困難・誤嚥リスク・体位障害・薬剤用量調整が特有の課題。IBWで薬剤量計算。", example:"Obese patient anesthesia required ramped positioning and awake fiberoptic intubation.", cat:"common", level:"intermediate", dept:"ANES" },
{ en:"Pediatric anesthesia", de:"Kinderanästhesie", abbr:"", ja:"小児麻酔", note:"体重・解剖学的特徴（細い気道・大きな後頭部）・生理的特性（高RR・高HR）への対応が必要。", example:"Pediatric anesthesia required careful dosing and age-appropriate airway management.", cat:"common", level:"intermediate", dept:"ANES" },
{ en:"Acute otitis media", de:"Akute Otitis media", abbr:"AOM", ja:"急性中耳炎", note:"鼓膜の発赤・膨隆・発熱・耳痛。小児に多い。肺炎球菌・インフルエンザ菌が原因菌。アモキシシリン。", example:"Acute otitis media was treated with amoxicillin for 7 days.", cat:"diagnosis", level:"basic", dept:"ENT" },
{ en:"Otitis media with effusion", de:"Seromuzotitis", abbr:"OME", ja:"滲出性中耳炎", note:"中耳に液体貯留するが急性感染徴候がない状態。伝音性難聴の原因。チューブ挿入を考慮。", example:"Otitis media with effusion caused a 30 dB conductive hearing loss in the child.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Tympanostomy tube", de:"Paukendrainage", abbr:"", ja:"鼓膜チューブ（グロメット）", note:"滲出性中耳炎・反復性急性中耳炎への治療。鼓膜に小チューブを留置して換気を改善。", example:"Tympanostomy tubes were inserted for recurrent otitis media with effusion.", cat:"treatment", level:"intermediate", dept:"ENT" },
{ en:"Cholesteatoma surgery", de:"Cholesteatomoperation", abbr:"", ja:"真珠腫手術", note:"後天性コレステアトーマの外科的切除。乳突削開術・鼓室形成術。再発に注意し長期経過観察。", example:"Cholesteatoma was removed via canal wall down mastoidectomy.", cat:"treatment", level:"advanced", dept:"ENT" },
{ en:"Adenotonsillectomy", de:"Adenotonsillektomie", abbr:"T&A", ja:"扁桃腺・アデノイド切除術", note:"反復性扁桃炎・OSAに対する手術。小児に多い。術後出血（術後24時間・5〜7日目）に注意。", example:"Adenotonsillectomy was performed for the child with severe OSA and tonsillar hypertrophy.", cat:"treatment", level:"basic", dept:"ENT" },
{ en:"Functional endoscopic sinus surgery", de:"Funktionelle endoskopische Nasennebenhöhlenchirurgie", abbr:"FESS", ja:"機能的内視鏡下副鼻腔手術", note:"慢性副鼻腔炎への内視鏡手術。副鼻腔の開放・換気改善が目的。局所麻酔または全身麻酔で実施。", example:"FESS was performed for chronic sinusitis unresponsive to medical treatment.", cat:"treatment", level:"intermediate", dept:"ENT" },
{ en:"Nasal polyposis", de:"Nasenpolypen", abbr:"", ja:"鼻茸（鼻ポリープ）", note:"鼻腔・副鼻腔粘膜の浮腫性隆起。慢性副鼻腔炎・喘息に合併。ステロイド点鼻・FESS。", example:"Nasal polyposis was causing nasal obstruction and anosmia.", cat:"diagnosis", level:"basic", dept:"ENT" },
{ en:"Anosmia", de:"Anosmie", abbr:"", ja:"嗅覚消失", note:"嗅覚の完全消失。副鼻腔炎・ウイルス感染（COVID-19）・外傷・神経疾患が原因。", example:"Anosmia after COVID-19 infection persisted for 3 months.", cat:"symptom", level:"basic", dept:"ENT" },
{ en:"Dysphonia", de:"Dysphonie", abbr:"", ja:"嗄声（声がれ）", note:"音声の異常。声帯ポリープ・声帯麻痺・反回神経麻痺・腫瘍が原因。喉頭鏡で評価。", example:"Dysphonia lasting more than 3 weeks required laryngoscopy to exclude malignancy.", cat:"symptom", level:"basic", dept:"ENT" },
{ en:"Vocal cord paralysis", de:"Stimmbandlähmung", abbr:"", ja:"声帯麻痺", note:"反回神経麻痺による声帯運動障害。一側性（嗄声）/ 両側性（気道閉塞）。甲状腺・食道・肺の疾患。", example:"Left vocal cord paralysis was caused by a thoracic aortic aneurysm compressing the recurrent laryngeal nerve.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Laryngeal cancer", de:"Larynxkarzinom", abbr:"", ja:"喉頭癌", note:"扁平上皮癌が最多。喫煙・飲酒がリスク因子。嗄声・嚥下障害・頸部リンパ節腫脹。手術・放射線・化学療法。", example:"Laryngeal cancer was detected early due to persistent hoarseness.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Neck dissection", de:"Neck Dissection", abbr:"ND", ja:"頸部郭清術", note:"頭頸部癌のリンパ節転移に対する手術。根治的・選択的・改変根治的の種類がある。", example:"Selective neck dissection was performed for the oral cancer with N1 disease.", cat:"treatment", level:"intermediate", dept:"ENT" },
{ en:"Parotid gland tumor", de:"Parotistumor", abbr:"", ja:"耳下腺腫瘍", note:"多形腺腫（良性最多）/ ワルチン腫瘍 / 粘表皮癌（悪性最多）。耳下腺摘出術。顔面神経保護が重要。", example:"A parotid gland tumor was excised with facial nerve monitoring.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Dizziness evaluation", de:"Schwindelabklärung", abbr:"", ja:"めまいの評価", note:"BPPV・メニエール病・前庭神経炎・中枢性（脳幹・小脳）を鑑別。HINTs試験・Dix-Hallpike。", example:"Dizziness evaluation using HINTS criteria excluded a central cause.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Dix-Hallpike test", de:"Dix-Hallpike-Test", abbr:"", ja:"ディックス・ホールパイクテスト", note:"BPPVの診断。後半規管型BPPVで眼振・めまい誘発。陽性なら耳石置換法（エプリー法）で治療。", example:"Dix-Hallpike test was positive on the right, confirming posterior canal BPPV.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Urodynamic study", de:"Urodynamische Untersuchung", abbr:"UDS", ja:"尿流動態検査", note:"膀胱充満・排尿時の圧・流量を測定。過活動膀胱・腹圧性尿失禁・神経因性膀胱の鑑別。", example:"Urodynamic study confirmed detrusor overactivity as the cause of urgency incontinence.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Uroflowmetry", de:"Uroflowmetrie", abbr:"", ja:"尿流量測定", note:"排尿速度・尿流パターンを記録。最大尿流量<15mL/secで閉塞・排尿障害を示唆。", example:"Uroflowmetry showed a plateau pattern suggesting bladder outlet obstruction.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Prostate biopsy", de:"Prostatabiopsie", abbr:"", ja:"前立腺生検", note:"PSA上昇・直腸指診異常例に経直腸または経会陰的に実施。グリーソンスコアで悪性度評価。", example:"Transrectal prostate biopsy confirmed Gleason score 7 adenocarcinoma.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Gleason score", de:"Gleason-Score", abbr:"", ja:"グリーソンスコア", note:"前立腺癌の悪性度評価。一次パターン＋二次パターン（各1〜5）の合計。6が低悪性度・10が最高悪性度。", example:"Gleason score 4+3=7 indicated intermediate-risk prostate cancer.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Active surveillance prostate cancer", de:"Aktive Überwachung beim Prostatakarzinom", abbr:"AS", ja:"前立腺癌の積極的監視療法", note:"低リスク前立腺癌の治療延期戦略。PSA・MRI・生検で経過観察。過剰治療回避が目的。", example:"Active surveillance was chosen for the low-risk prostate cancer in the elderly patient.", cat:"treatment", level:"intermediate", dept:"URO" },
{ en:"Radical prostatectomy", de:"Radikale Prostatektomie", abbr:"RP", ja:"根治的前立腺摘除術", note:"限局性前立腺癌の根治手術。開腹・腹腔鏡・ロボット支援。術後尿失禁・勃起障害が合併症。", example:"Robotic radical prostatectomy was performed for the localized high-risk prostate cancer.", cat:"treatment", level:"intermediate", dept:"URO" },
{ en:"Hematuria workup", de:"Hämaturieabklärung", abbr:"", ja:"血尿の精査", note:"尿細胞診・尿培養・腹部超音波・CT尿路造影・膀胱鏡。悪性腫瘍・結石・感染を鑑別。", example:"Hematuria workup revealed a bladder tumor that was resected transurethrally.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Transurethral resection", de:"Transurethrale Resektion", abbr:"TUR", ja:"経尿道的切除術", note:"TURP（前立腺）/ TURBT（膀胱腫瘍）。尿道から内視鏡を挿入して切除。TUR症候群（低Na血症）に注意。", example:"Transurethral resection of bladder tumor confirmed high-grade urothelial carcinoma.", cat:"treatment", level:"intermediate", dept:"URO" },
{ en:"Refractive error", de:"Refraktionsfehler", abbr:"", ja:"屈折異常", note:"近視（myopia）/ 遠視（hyperopia）/ 乱視（astigmatism）/ 老視（presbyopia）。眼鏡・コンタクト・レーシックで矯正。", example:"Refractive error was corrected with glasses, achieving 20/20 visual acuity.", cat:"diagnosis", level:"basic", dept:"OPH" },
{ en:"Diabetic macular edema", de:"Diabetisches Makulaödem", abbr:"DME", ja:"糖尿病黄斑浮腫", note:"糖尿病網膜症に伴う黄斑部浮腫。視力低下の主原因。Anti-VEGF・レーザー・ステロイドで治療。", example:"Diabetic macular edema was treated with monthly anti-VEGF injections.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Proliferative diabetic retinopathy", de:"Proliferative diabetische Retinopathie", abbr:"PDR", ja:"増殖糖尿病網膜症", note:"新生血管形成・硝子体出血・牽引性網膜剥離。汎網膜光凝固・硝子体手術が治療。", example:"Proliferative diabetic retinopathy was treated with panretinal photocoagulation.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Retinal vein occlusion", de:"Retinaler Venenverschluss", abbr:"RVO", ja:"網膜静脈閉塞症", note:"分枝型（BRVO）/ 中心型（CRVO）。黄斑浮腫・視力低下。Anti-VEGF・レーザーで治療。血管リスク管理。", example:"Central retinal vein occlusion caused sudden visual loss in the hypertensive patient.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Acute angle closure glaucoma", de:"Akutes Winkelblockglaukom", abbr:"AACG", ja:"急性閉塞隅角緑内障", note:"虹彩が隅角を閉塞→眼圧急上昇。激しい眼痛・頭痛・悪心・角膜混濁。緊急レーザー虹彩切開術。", example:"Acute angle closure glaucoma was relieved with emergency laser peripheral iridotomy.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Cataract grading", de:"Kataraktgraduierung", abbr:"", ja:"白内障の分類・程度評価", note:"核白内障・皮質白内障・後嚢下白内障の種類と混濁度で分類。視力・生活障害度で手術時期を決定。", example:"Nuclear cataract grading of 3+ indicated significant visual impairment requiring surgery.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Phacoemulsification", de:"Phakoemulsifikation", abbr:"Phaco", ja:"超音波水晶体乳化吸引術", note:"超音波で水晶体を乳化・吸引して人工レンズを挿入する白内障手術。現在の標準術式。", example:"Phacoemulsification with IOL implantation restored vision to 20/25.", cat:"treatment", level:"intermediate", dept:"OPH" },
{ en:"Intraocular lens", de:"Intraokularlinse", abbr:"IOL", ja:"眼内レンズ（IOL）", note:"白内障手術で挿入する人工水晶体。単焦点・多焦点・トーリック（乱視矯正）の種類がある。", example:"A multifocal IOL was chosen to reduce dependence on glasses after cataract surgery.", cat:"treatment", level:"intermediate", dept:"OPH" },
{ en:"Vitreous hemorrhage", de:"Glaskörperblutung", abbr:"", ja:"硝子体出血", note:"糖尿病網膜症・網膜裂孔・外傷で発生。飛蚊症・視力低下・「煙が立つ」症状。超音波で評価。", example:"Vitreous hemorrhage was observed conservatively and cleared over 3 months.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"PET scan", de:"PET-Untersuchung", abbr:"PET", ja:"PET検査", note:"FDGを用いた代謝機能画像。悪性腫瘍の病期・再発・治療効果判定に使用。ブドウ糖代謝亢進部位が高信号。", example:"PET scan showed hypermetabolic activity in the mediastinal lymph nodes, suggesting lymphoma.", cat:"diagnosis", level:"intermediate", dept:"RAD" },
{ en:"SUV", de:"Standardized Uptake Value", abbr:"SUV", ja:"標準化取り込み値（SUV）", note:"PETでのFDG取り込み量の指標。SUV>2.5で悪性を疑う目安。治療前後の比較で効果判定。", example:"Maximum SUV of 8.2 in the lung mass was highly suspicious for malignancy.", cat:"diagnosis", level:"advanced", dept:"RAD" },
{ en:"Radiologic response assessment", de:"Radiologische Ansprechbewertung", abbr:"", ja:"画像での治療効果判定", note:"RECIST基準・mRECIST・PERCIST。固形腫瘍の治療前後の画像比較。CR/PR/SD/PDで分類。", example:"Radiologic response assessment showed partial response after 3 cycles of chemotherapy.", cat:"diagnosis", level:"intermediate", dept:"RAD" },
{ en:"MRI contraindications", de:"MRT-Kontraindikationen", abbr:"", ja:"MRI禁忌", note:"心臓ペースメーカー（条件付きOKのものも）・人工内耳・金属異物・重症閉所恐怖症。安全確認が必須。", example:"MRI contraindications were screened before the scan to ensure patient safety.", cat:"common", level:"basic", dept:"RAD" },
{ en:"Antepartum hemorrhage", de:"Antepartale Blutung", abbr:"APH", ja:"前置出血（分娩前出血）", note:"妊娠20週以降の性器出血。前置胎盤・常位胎盤早期剥離が主原因。緊急対応が必要。", example:"Antepartum hemorrhage required urgent assessment for placenta previa.", cat:"diagnosis", level:"intermediate", dept:"OB" },
{ en:"Placenta accreta spectrum", de:"Placenta accreta Spektrum", abbr:"PAS", ja:"癒着胎盤スペクトラム", note:"胎盤の子宮筋層への異常侵入。前置胎盤＋帝王切開既往が高リスク。術中大量出血・子宮摘出。", example:"Placenta accreta spectrum was suspected on MRI, requiring multidisciplinary delivery planning.", cat:"diagnosis", level:"advanced", dept:"OB" },
{ en:"Oxytocin augmentation", de:"Oxytozinaugmentation", abbr:"", ja:"オキシトシン陣痛促進", note:"分娩第1期の微弱陣痛に使用。胎児モニタリング必須。過強陣痛・胎児機能不全に注意。", example:"Oxytocin augmentation was started for slow progress in the active phase of labor.", cat:"treatment", level:"intermediate", dept:"OB" },
{ en:"Fetal scalp electrode", de:"Fetale Kopfhautelektrode", abbr:"FSE", ja:"胎児頭皮電極", note:"内測CTG用の電極。羊水混濁・外測CTGが不明確な時に使用。破水後に留置。", example:"Fetal scalp electrode was applied for continuous monitoring in the active labor.", cat:"diagnosis", level:"advanced", dept:"OB" },
{ en:"Vacuum extraction", de:"Vakuumextraktion", abbr:"VE", ja:"吸引分娩", note:"吸引カップを胎頭に装着して娩出を補助。第2期遷延・胎児機能不全に適応。3回失敗で中止。", example:"Vacuum extraction was performed for the prolonged second stage of labor.", cat:"treatment", level:"intermediate", dept:"OB" },
{ en:"Forceps delivery", de:"Zangengeburt", abbr:"", ja:"鉗子分娩", note:"分娩鉗子を胎頭に装着して娩出を補助。習熟が必要。母体・胎児外傷リスク。", example:"Forceps delivery was performed by the experienced obstetrician for the distressed fetus.", cat:"treatment", level:"advanced", dept:"OB" },
{ en:"Intrauterine fetal demise", de:"Intrauteriner Fruchttod", abbr:"IUFD", ja:"子宮内胎児死亡", note:"妊娠20週以降の胎児死亡。超音波で心拍消失を確認。死因検索・両親へのグリーフケアが重要。", example:"Intrauterine fetal demise was confirmed by absence of cardiac activity on ultrasound.", cat:"diagnosis", level:"intermediate", dept:"OB" },
{ en:"Can you stand up for me?", de:"Können Sie für mich aufstehen?", abbr:"", ja:"立っていただけますか？", note:"立位評価・歩行開始の指示。安全確認（めまい・ふらつき）を必ず行ってから立たせる。", example:"Can you stand up for me? Take your time and hold the rail.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you walk to the end of the room?", de:"Können Sie bis ans Ende des Zimmers gehen?", abbr:"", ja:"部屋の端まで歩いてみてください。", note:"歩行評価の指示。跛行・バランス・歩行補助具の必要性を確認。", example:"Can you walk to the end of the room and back for me?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Does it hurt when I press here?", de:"Tut es weh, wenn ich hier drücke?", abbr:"", ja:"ここを押すと痛みますか？", note:"圧痛確認の基本フレーズ。表情・反応を観察しながら確認する。", example:"Does it hurt when I press here? What about here?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Take a big breath in.", de:"Atmen Sie tief ein.", abbr:"", ja:"大きく息を吸ってください。", note:"聴診・肺機能評価時の指示。吸気相の呼吸音を評価するために使用。", example:"Take a big breath in through your mouth and hold it.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Breathe out slowly.", de:"Atmen Sie langsam aus.", abbr:"", ja:"ゆっくり息を吐いてください。", note:"呼気相の呼吸音評価・呼吸練習の指示。COPDの呼吸リハビリにも使用。", example:"Breathe out slowly through pursed lips.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you open your mouth wide?", de:"Können Sie Ihren Mund weit öffnen?", abbr:"", ja:"口を大きく開けてください。", note:"口腔内・咽頭評価の指示。扁桃・後壁・舌根の観察。TMJ障害の評価にも使用。", example:"Can you open your mouth wide so I can examine your throat?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Swallow for me.", de:"Schlucken Sie für mich.", abbr:"", ja:"飲み込んでみてください。", note:"嚥下機能評価の指示。甲状腺触診・嚥下障害のスクリーニングに使用。", example:"Swallow for me while I feel your thyroid gland.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you smile for me?", de:"Können Sie für mich lächeln?", abbr:"", ja:"笑ってみてください。", note:"顔面神経（CNVII）の評価指示。口角の下垂・対称性を確認。脳卒中評価（FAST）。", example:"Can you smile for me? Now show me your teeth.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Raise your eyebrows.", de:"Heben Sie die Augenbrauen.", abbr:"", ja:"眉を上げてください。", note:"顔面神経上枝（前頭枝）の評価。中枢性顔面麻痺では保たれる（額は保存）。", example:"Raise your eyebrows as high as you can.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Close your eyes tight.", de:"Schließen Sie die Augen fest.", abbr:"", ja:"目をしっかり閉じてください。", note:"顔面神経・眼輪筋の評価。麻痺側では完全閉瞼できない（兎眼）。", example:"Close your eyes as tight as you can and don't let me open them.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Clench your teeth.", de:"Beißen Sie die Zähne zusammen.", abbr:"", ja:"歯をくいしばってください。", note:"三叉神経運動枝（咀嚼筋）の評価。側頭筋・咬筋の収縮を触れて確認。", example:"Clench your teeth so I can feel the muscles in your jaw.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you hear this?", de:"Können Sie das hören?", abbr:"", ja:"これが聞こえますか？", note:"聴力の簡易スクリーニング。指こすり法・音叉（Rinne・Weber）で評価。耳音響放射との比較。", example:"Can you hear this? What about on the other side?", cat:"common", level:"basic", dept:"GEN" },
{ en:"I'm going to check your reflexes.", de:"Ich überprüfe jetzt Ihre Reflexe.", abbr:"", ja:"反射を確認します。", note:"腱反射検査前の説明。リラックスが重要であることを伝え、協力を得る。", example:"I'm going to check your reflexes with this hammer. Please relax.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you feel this?", de:"Können Sie das fühlen?", abbr:"", ja:"これを感じますか？", note:"感覚検査の指示。綿棒・針先・温冷・音叉で評価。目を閉じた状態で確認する。", example:"Can you feel this? Is it the same on both sides?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Is this sharp or dull?", de:"Ist das scharf oder stumpf?", abbr:"", ja:"尖っていますか、鈍いですか？", note:"痛覚（鋭/鈍）の識別テスト。閉眼で評価。感覚障害の定性的評価に使用。", example:"Is this sharp or dull? Close your eyes and tell me what you feel.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Wiggle your fingers.", de:"Bewegen Sie Ihre Finger.", abbr:"", ja:"指を動かしてください。", note:"指の運動・感覚評価の指示。末梢循環・神経機能の確認にも使用。", example:"Can you wiggle your fingers for me? Now your toes.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you push against my hand?", de:"Können Sie gegen meine Hand drücken?", abbr:"", ja:"私の手に力を入れて押してみてください。", note:"四肢の筋力評価の指示。上肢・下肢の各筋群を系統的に評価する。", example:"Can you push against my hand as hard as you can?", cat:"common", level:"basic", dept:"GEN" },
{ en:"I'm going to take your temperature.", de:"Ich messe jetzt Ihre Körpertemperatur.", abbr:"", ja:"体温を測ります。", note:"体温測定前の説明。測定部位（耳・腋窩・口腔・直腸）を伝える。", example:"I'm going to take your temperature with this ear thermometer.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Your blood pressure is a little high.", de:"Ihr Blutdruck ist etwas erhöht.", abbr:"", ja:"血圧が少し高めです。", note:"高血圧の結果を伝える表現。数値を示し、フォローアップの必要性を説明する。", example:"Your blood pressure is a little high today — 148/92. Have you been taking your medication?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Your heart rate is a bit fast.", de:"Ihr Puls ist etwas schnell.", abbr:"", ja:"脈が少し速いですね。", note:"頻脈の結果を伝える表現。症状・原因（不安・発熱・甲状腺疾患）を合わせて確認。", example:"Your heart rate is a bit fast at 105. Are you feeling anxious or short of breath?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Your oxygen level is low.", de:"Ihr Sauerstoffsättigungswert ist niedrig.", abbr:"", ja:"酸素飽和度が低いです。", note:"低酸素血症の結果を伝える表現。数値を示し、原因評価と治療開始を説明する。", example:"Your oxygen level is low at 90%. I'm going to give you some oxygen.", cat:"common", level:"basic", dept:"GEN" },
{ en:"I need to clean the wound.", de:"Ich muss die Wunde reinigen.", abbr:"", ja:"傷を洗浄します。", note:"創部処置前の説明。痛みがあることを事前に伝える。生食・消毒薬の使用を説明。", example:"I need to clean the wound — it may sting a little.", cat:"common", level:"basic", dept:"GEN" },
{ en:"This will numb the area.", de:"Das wird die Stelle betäuben.", abbr:"", ja:"この部位の感覚がなくなります。", note:"局所麻酔薬注射前の説明。完全に麻酔がきくまで数分かかることも伝える。", example:"This will numb the area — you'll feel some pressure but not pain.", cat:"common", level:"basic", dept:"GEN" },
{ en:"I'm going to give you a small injection.", de:"Ich gebe Ihnen eine kleine Injektion.", abbr:"", ja:"少し注射をします。", note:"注射前の説明。筋注・皮下注・静注のどれかを伝え、針を刺すことを予告する。", example:"I'm going to give you a small injection in your arm for the pain.", cat:"common", level:"basic", dept:"GEN" },
{ en:"We'll keep you comfortable.", de:"Wir sorgen für Ihr Wohlbefinden.", abbr:"", ja:"苦痛のないようにします。", note:"緩和ケア・疼痛管理の方針を伝える表現。患者・家族への安心感を与える一言。", example:"We'll keep you comfortable and make sure you're not in pain.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Is there anything I can explain more clearly?", de:"Gibt es etwas, das ich klarer erklären kann?", abbr:"", ja:"もっとわかりやすく説明できることはありますか？", note:"説明後の理解度確認。患者が遠慮なく質問できる雰囲気を作る表現。", example:"Is there anything I can explain more clearly? It's important that you understand.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Take it one day at a time.", de:"Nehmen Sie es einen Tag nach dem anderen.", abbr:"", ja:"一日一日を大切にしてください。", note:"重篤な診断・長期療養を受け入れる患者への励ましの言葉。", example:"This is a lot to take in. Take it one day at a time and we'll support you.", cat:"common", level:"basic", dept:"GEN" },
{ en:"You are in safe hands.", de:"Sie sind in guten Händen.", abbr:"", ja:"安心してお任せください。", note:"患者の不安を和らげる表現。特に処置前・手術前に使う。", example:"You are in safe hands — our team has done this procedure many times.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Contact dermatitis", de:"Kontaktdermatitis", abbr:"", ja:"接触性皮膚炎", note:"アレルギー性（感作後の遅延型反応）/ 刺激性（直接的な化学的刺激）に分類。パッチテストで鑑別。", example:"Allergic contact dermatitis to nickel was confirmed by patch testing.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Atopic dermatitis", de:"Atopische Dermatitis", abbr:"AD", ja:"アトピー性皮膚炎", note:"遺伝的・免疫学的・環境的因子による慢性炎症性皮膚疾患。掻痒・乾燥・湿疹性変化。ステロイド・保湿剤。", example:"Atopic dermatitis was managed with topical corticosteroids and regular emollients.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Seborrheic dermatitis", de:"Seborrhoische Dermatitis", abbr:"", ja:"脂漏性皮膚炎", note:"頭皮・顔面（鼻唇溝）・耳後部の脂漏部位に生じる慢性皮膚炎。Malassezia菌関与。抗真菌薬・ステロイド。", example:"Seborrheic dermatitis was treated with ketoconazole shampoo and mild topical steroid.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Rosacea", de:"Rosazea", abbr:"", ja:"酒さ（ロザセア）", note:"顔面の慢性炎症性疾患。紅斑・血管拡張・丘疹・膿疱・鼻瘤。日光・アルコール・刺激物が増悪因子。", example:"Rosacea was managed with topical metronidazole and sun protection.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Acne vulgaris", de:"Acne vulgaris", abbr:"", ja:"尋常性ざ瘡（ニキビ）", note:"毛包脂腺系の慢性炎症。面皰・丘疹・膿疱・結節。Cutibacterium acnesが関与。外用薬・抗菌薬・イソトレチノイン。", example:"Moderate acne vulgaris was treated with topical benzoyl peroxide and clindamycin.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Isotretinoin", de:"Isotretinoin", abbr:"", ja:"イソトレチノイン（レチノイン酸）", note:"重症ざ瘡の経口治療薬。催奇形性（避妊必須）・肝機能障害・脂質異常に注意。TDMと経過観察が必須。", example:"Isotretinoin was prescribed for severe nodular acne unresponsive to antibiotics.", cat:"treatment", level:"intermediate", dept:"DERM" },
{ en:"Urticaria management", de:"Urtikariatherapie", abbr:"", ja:"蕁麻疹の管理", note:"急性（感染・食物・薬剤）/ 慢性（自己免疫・特発性）に分類。第2世代抗ヒスタミン薬が第一選択。", example:"Chronic urticaria was managed with daily cetirizine and trigger avoidance.", cat:"treatment", level:"basic", dept:"DERM" },
{ en:"Drug hypersensitivity reaction", de:"Arzneimittelüberempfindlichkeit", abbr:"DHR", ja:"薬剤過敏反応", note:"薬疹（最多）からSJS/TEN（重篤）まで様々。原因薬の特定・中止が最重要。ステロイド・IVIGを使用することも。", example:"Drug hypersensitivity reaction to sulfonamide caused a widespread maculopapular rash.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"Tinea corporis", de:"Tinea corporis", abbr:"", ja:"体部白癬（タムシ）", note:"皮膚糸状菌による体幹・四肢の表在性真菌感染。輪状紅斑・中心治癒。外用抗真菌薬で治療。", example:"Tinea corporis was treated with topical terbinafine for 2 weeks.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Onychomycosis", de:"Onychomykose", abbr:"", ja:"爪白癬", note:"爪の真菌感染。爪の肥厚・混濁・変色。経口テルビナフィン・イトラコナゾールが有効。治療期間が長い。", example:"Onychomycosis of the toenails was treated with oral terbinafine for 12 weeks.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Impetigo treatment", de:"Impetigobehandlung", abbr:"", ja:"伝染性膿痂疹の治療", note:"黄色ブドウ球菌・A群溶連菌による皮膚浅在性感染。外用ムピロシン・経口抗菌薬。接触感染予防。", example:"Impetigo was treated with mupirocin ointment and improved within one week.", cat:"treatment", level:"basic", dept:"DERM" },
{ en:"Wound dressing types", de:"Wundauflagearten", abbr:"", ja:"創傷被覆材の種類", note:"ガーゼ・ハイドロコロイド・フォーム・アルジネート・親水性ファイバー。創の状態・滲出液量で選択。", example:"A hydrocolloid dressing was chosen for the clean partial-thickness wound.", cat:"treatment", level:"intermediate", dept:"DERM" },
{ en:"Photosensitivity reaction", de:"Photosensitivitätsreaktion", abbr:"", ja:"光線過敏反応", note:"日光照射部位（顔・頸部・手背）の皮膚炎。薬剤（テトラサイクリン・NSAIDS）/ 全身性疾患（SLE）が原因。", example:"Photosensitivity reaction was caused by the patient's doxycycline therapy.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"Hidradenitis suppurativa", de:"Hidradenitis suppurativa", abbr:"HS", ja:"化膿性汗腺炎", note:"アポクリン腺の慢性炎症。腋窩・鼠径・殿部の結節・膿瘍・瘻孔。アダリムマブ・手術で治療。", example:"Hidradenitis suppurativa in the axilla was treated with adalimumab.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"Skin cancer prevention", de:"Hautkrebsprävention", abbr:"", ja:"皮膚癌予防", note:"紫外線防護（SPF30以上）・定期的な皮膚検診・自己観察（ABCDE）。白色人種・屋外労働者が高リスク。", example:"Skin cancer prevention was reinforced with daily sunscreen and annual skin checks.", cat:"common", level:"basic", dept:"DERM" },
{ en:"Molluscum contagiosum", de:"Molluscum contagiosum", abbr:"", ja:"伝染性軟属腫（水いぼ）", note:"ポックスウイルスによる皮膚感染。光沢のある臍窩を持つ丘疹。小児・免疫不全者に多い。自然治癒あり。", example:"Molluscum contagiosum in the child was managed with watchful waiting.", cat:"diagnosis", level:"basic", dept:"DERM" },
{ en:"Vitiligo", de:"Vitiligo", abbr:"", ja:"白斑（尋常性白斑）", note:"メラノサイトの自己免疫的破壊による皮膚脱色素。自己免疫疾患との合併多い。外用ステロイド・光線療法。", example:"Vitiligo on the hands was treated with narrowband UVB phototherapy.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"Psoriatic arthritis skin finding", de:"Psoriatische Arthritis Hautbefund", abbr:"", ja:"乾癬性関節炎の皮膚所見", note:"乾癬（銀白色鱗屑を伴う紅色局面）を関節炎患者で確認。爪乾癬（点状陥凹・爪甲剥離）も重要。", example:"Psoriatic plaques on the elbows confirmed the diagnosis of psoriatic arthritis.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"AKI staging", de:"AKI-Klassifikation", abbr:"", ja:"AKI病期分類（KDIGO基準）", note:"Stage 1（Cr×1.5〜1.9倍or+0.3mg/dL）/ Stage 2（Cr×2〜2.9倍）/ Stage 3（Cr×3倍以上or透析）。", example:"AKI was staged as KDIGO Stage 2 based on serum creatinine doubling.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Prerenal azotemia", de:"Prärenale Azotämie", abbr:"", ja:"腎前性腎不全", note:"腎血流低下による可逆的なBUN/Cr上昇。BUN/Cr>20・FeNa<1%。輸液・血圧管理で改善。", example:"Prerenal azotemia resolved with aggressive IV fluid resuscitation.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Intrinsic renal failure", de:"Intrinsisches Nierenversagen", abbr:"", ja:"腎性腎不全", note:"ATN（最多）・糸球体腎炎・間質性腎炎・血管障害。FeNa>2%・尿沈渣に顆粒円柱。原因治療。", example:"Intrinsic renal failure from aminoglycoside nephrotoxicity required dose adjustment.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Postrenal obstruction", de:"Postrenale Obstruktion", abbr:"", ja:"腎後性腎不全", note:"尿路閉塞による腎障害。前立腺肥大・尿管結石・腫瘍が原因。超音波で水腎症を確認。緊急ドレナージ。", example:"Postrenal obstruction by bladder outlet obstruction was relieved with urethral catheterization.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Potassium management in CKD", de:"Kaliummanagement bei CKD", abbr:"", ja:"CKDのカリウム管理", note:"高K血症リスク（GFR<30）。食事指導（低K食）・カリウム吸着薬（ジルコニウムシクロ珪酸）・透析。", example:"Potassium management included dietary restriction and patiromer to prevent hyperkalemia.", cat:"treatment", level:"intermediate", dept:"NEPH" },
{ en:"Phosphate management", de:"Phosphatmanagement", abbr:"", ja:"リン管理（CKD）", note:"高リン血症（GFR<30）。リン吸着薬（炭酸カルシウム・セベラマー）・低リン食。血管石灰化予防。", example:"Phosphate binders were prescribed to manage hyperphosphatemia in the dialysis patient.", cat:"treatment", level:"intermediate", dept:"NEPH" },
{ en:"Vitamin D deficiency in CKD", de:"Vitamin-D-Mangel bei CKD", abbr:"", ja:"CKDのビタミンD欠乏", note:"活性型ビタミDの腎での産生低下。PTH上昇・骨病変・免疫低下。活性型ビタミンD補充。", example:"Active vitamin D was prescribed to correct deficiency and suppress PTH in CKD.", cat:"treatment", level:"intermediate", dept:"NEPH" },
{ en:"Dialysis disequilibrium syndrome", de:"Dialyse-Dysäquilibrium-Syndrom", abbr:"DDS", ja:"透析不均衡症候群", note:"透析初回・高BUN患者での急速な溶質除去による脳浮腫。頭痛・悪心・痙攣・意識障害。緩徐な透析で予防。", example:"Dialysis disequilibrium syndrome was prevented with a short first dialysis session.", cat:"diagnosis", level:"advanced", dept:"NEPH" },
{ en:"Tunnel infection", de:"Tunnelinfekt", abbr:"", ja:"カテーテルトンネル感染", note:"透析カテーテルの皮下トンネル部の感染。発赤・疼痛・膿性排液。カテーテル抜去・抗菌薬投与。", example:"Tunnel infection around the dialysis catheter required catheter removal.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Exit site infection", de:"Austrittsstelleninfektion", abbr:"", ja:"出口部感染（透析カテーテル）", note:"カテーテル出口部の感染。発赤・滲出液。局所抗菌薬・経口抗菌薬で治療。進行でトンネル感染へ。", example:"Exit site infection was treated with topical mupirocin and improved within one week.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Renal biopsy indication", de:"Nierenbiopsie-Indikation", abbr:"", ja:"腎生検の適応", note:"原因不明のネフローゼ症候群・急速進行性腎炎・AKI・タンパク尿2g/日以上・腎機能低下原因評価。", example:"Renal biopsy was indicated for the unexplained nephrotic syndrome in the adult patient.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Cryoglobulinemia", de:"Kryoglobulinämie", abbr:"", ja:"クリオグロブリン血症", note:"低温で沈殿するIg複合体（クリオグロブリン）による全身性血管炎。HCV感染に多い。腎炎・紫斑・末梢神経炎。", example:"Cryoglobulinemia associated with hepatitis C caused membranoproliferative glomerulonephritis.", cat:"diagnosis", level:"advanced", dept:"NEPH" },
{ en:"Nephrocalcinosis", de:"Nephrokalzinose", abbr:"", ja:"腎石灰化症", note:"腎実質へのカルシウム沈着。高Ca血症・高シュウ酸尿・遠位尿細管アシドーシスが原因。画像で確認。", example:"Nephrocalcinosis was detected on ultrasound in the patient with hypercalcemia.", cat:"diagnosis", level:"advanced", dept:"NEPH" },
{ en:"Liver cirrhosis complications", de:"Leberzirrhosekomplikationen", abbr:"", ja:"肝硬変の合併症", note:"食道静脈瘤・腹水・自発性細菌性腹膜炎・肝性脳症・肝腎症候群・HCC。定期的スクリーニングが重要。", example:"Liver cirrhosis complications were screened with 6-monthly ultrasound and endoscopy.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Model for end-stage liver disease", de:"MELD-Score", abbr:"MELD score", ja:"MELDスコア", note:"肝移植の優先順位・予後評価スコア。Cr・Bil・INR・Na使用。10点以上で肝移植検討。", example:"MELD score of 22 indicated high 3-month mortality and liver transplant evaluation.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Hepatic encephalopathy grade", de:"West-Haven-Klassifikation", abbr:"West-Haven", ja:"肝性脳症のグレード分類", note:"Grade 0（潜在性）〜IV（昏睡）のWest-Haven分類。ラクツロース・リファキシミンで治療。", example:"Hepatic encephalopathy grade III required ICU admission and lactulose via NG tube.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Hepatorenal syndrome", de:"Hepatorenales Syndrom", abbr:"HRS", ja:"肝腎症候群", note:"重篤な肝硬変での腎機能障害。Type 1（急性）/ Type 2（慢性）。テルリプレシン＋アルブミンが治療。", example:"Hepatorenal syndrome type 1 was treated with terlipressin and albumin infusion.", cat:"diagnosis", level:"advanced", dept:"GI" },
{ en:"Variceal bleeding management", de:"Management der Varizenblutung", abbr:"", ja:"静脈瘤出血の管理", note:"オクトレオチド静注＋内視鏡的静脈瘤結紮（EVL）＋抗菌薬（ノルフロキサシン）＋輸血が標準管理。", example:"Variceal bleeding was managed with octreotide, antibiotics, and urgent endoscopic banding.", cat:"treatment", level:"intermediate", dept:"GI" },
{ en:"Budd-Chiari syndrome", de:"Budd-Chiari-Syndrom", abbr:"", ja:"バッド・キアリ症候群", note:"肝静脈・下大静脈の閉塞による急性・慢性肝障害。腹水・肝腫大・疼痛。抗凝固・TIPS・肝移植。", example:"Budd-Chiari syndrome was confirmed by Doppler ultrasound showing absent hepatic vein flow.", cat:"diagnosis", level:"advanced", dept:"GI" },
{ en:"Celiac disease", de:"Zöliakie", abbr:"", ja:"セリアック病", note:"グルテンによる自己免疫性小腸障害。下痢・体重減少・貧血・骨粗鬆症。抗TTG抗体・小腸生検で診断。", example:"Celiac disease was confirmed by anti-TTG antibodies and duodenal biopsy showing villous atrophy.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Small intestinal bacterial overgrowth", de:"Dünndarmfehlbesiedlung", abbr:"SIBO", ja:"小腸内細菌過増殖（SIBO）", note:"小腸での細菌異常増殖。腹部膨満・下痢・吸収不良。水素呼気試験・リファキシミンで診断・治療。", example:"SIBO was diagnosed by a positive glucose hydrogen breath test.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Influenza management", de:"Grippemanagement", abbr:"", ja:"インフルエンザの管理", note:"発症48時間以内にオセルタミビル投与で効果。重症患者・ハイリスクは積極的に治療。ワクチン予防。", example:"Influenza was managed with oseltamivir started within 24 hours of symptom onset.", cat:"treatment", level:"basic", dept:"INFECT" },
{ en:"COVID-19 treatment", de:"COVID-19-Behandlung", abbr:"", ja:"COVID-19の治療", note:"軽症：ニルマトレルビル/リトナビル（発症5日以内）/ 中等症：レムデシビル / 重症：デキサメタゾン・バリシチニブ。", example:"COVID-19 pneumonia was treated with dexamethasone and remdesivir in the hypoxic patient.", cat:"treatment", level:"intermediate", dept:"INFECT" },
{ en:"Travel medicine", de:"Reisemedizin", abbr:"", ja:"渡航医学", note:"海外渡航前のワクチン接種・マラリア予防・衛生指導・渡航先別リスク評価。帰国後の発熱も評価。", example:"Travel medicine consultation included malaria prophylaxis and hepatitis A vaccination.", cat:"common", level:"intermediate", dept:"INFECT" },
{ en:"Wound infection signs", de:"Wundinfektionszeichen", abbr:"", ja:"創部感染の徴候", note:"Rubor（発赤）・Calor（熱感）・Tumor（腫脹）・Dolor（疼痛）・Functio laesa（機能障害）。壊死・異臭も重要。", example:"Wound infection signs including erythema and purulent discharge required antibiotic therapy.", cat:"diagnosis", level:"basic", dept:"INFECT" },
{ en:"Comprehensive geriatric assessment", de:"Umfassendes geriatrisches Assessment", abbr:"CGA", ja:"包括的高齢者評価", note:"身体機能・認知・栄養・抑うつ・社会環境を多面的に評価。高齢者の治療計画・退院支援に使用。", example:"Comprehensive geriatric assessment revealed functional decline and depression in the older patient.", cat:"diagnosis", level:"intermediate", dept:"IM" },
{ en:"Delirium prevention bundle", de:"Delirpräventionsbündel", abbr:"", ja:"せん妄予防バンドル", note:"見当識維持・早期離床・睡眠保護・視力・聴力補正・水分管理・疼痛管理。薬物療法より非薬物療法を優先。", example:"Delirium prevention bundle reduced ICU delirium incidence by 30%.", cat:"treatment", level:"intermediate", dept:"IM" },
{ en:"Deconditioning", de:"Dekonditionierung", abbr:"", ja:"廃用症候群", note:"安静・不動化による身体機能低下。筋萎縮・骨粗鬆症・起立性低血圧・褥瘡。早期離床が予防。", example:"Deconditioning from prolonged bed rest was addressed with daily physiotherapy.", cat:"diagnosis", level:"intermediate", dept:"IM" },
{ en:"Nutritional screening", de:"Ernährungsscreening", abbr:"", ja:"栄養スクリーニング", note:"NRS-2002・MNA・MUSTなどのツールで低栄養リスクを評価。栄養サポートチーム（NST）への相談。", example:"Nutritional screening identified malnutrition risk, prompting dietitian referral.", cat:"diagnosis", level:"basic", dept:"IM" },
{ en:"Albumin level", de:"Albuminspiegel", abbr:"", ja:"血清アルブミン値", note:"正常3.5〜5.0g/dL。低値で栄養不良・肝障害・炎症・腎症候群を示唆。浮腫・薬物結合にも影響。", example:"Low albumin of 2.8 g/dL indicated significant malnutrition requiring nutritional support.", cat:"diagnosis", level:"basic", dept:"IM" },
{ en:"What is your date of birth?", de:"Was ist Ihr Geburtsdatum?", abbr:"", ja:"生年月日はいつですか？", note:"患者確認の基本質問。名前と生年月日の2点確認が標準的な患者識別手順。", example:"What is your date of birth? I need to confirm your identity before the procedure.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Can you confirm your full name?", de:"Können Sie Ihren vollständigen Namen bestätigen?", abbr:"", ja:"フルネームを確認させてください。", note:"患者識別の基本。同姓同名の誤投薬・誤処置防止のために必須。", example:"Can you confirm your full name and date of birth before I give you the medication?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Do you have a living will?", de:"Haben Sie eine Patientenverfügung?", abbr:"", ja:"事前指示書はありますか？", note:"アドバンスディレクティブの確認。患者が判断能力を失った際の医療方針を尊重するために重要。", example:"Do you have a living will or any advance directives we should be aware of?", cat:"common", level:"intermediate", dept:"GEN" },
{ en:"Who is your next of kin?", de:"Wer ist Ihr nächster Angehöriger?", abbr:"", ja:"緊急連絡先はどなたですか？", note:"緊急連絡先・代理意思決定者の確認。重大な状況での家族への連絡・意思決定支援に必要。", example:"Who is your next of kin in case we need to contact someone?", cat:"common", level:"basic", dept:"GEN" },
{ en:"I need to review your medications.", de:"Ich muss Ihre Medikamente überprüfen.", abbr:"", ja:"お薬を確認させてください。", note:"入院時薬剤調整（メディケーションレコンシリエーション）。お薬手帳・処方箋の確認。", example:"I need to review your medications — do you have a medication list or your prescription bag?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Are you allergic to penicillin?", de:"Sind Sie allergisch gegen Penicillin?", abbr:"", ja:"ペニシリンにアレルギーはありますか？", note:"最も重要な薬剤アレルギー確認の一つ。反応の種類（発疹・アナフィラキシー）も確認する。", example:"Are you allergic to penicillin or any other antibiotics?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Have you eaten or drunk anything today?", de:"Haben Sie heute etwas gegessen oder getrunken?", abbr:"", ja:"今日は何か食べたり飲んだりしましたか？", note:"手術・検査前の絶食確認。いつ最後に食べたかを具体的に確認する。", example:"Have you eaten or drunk anything today? When was your last meal?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Please remove your jewelry.", de:"Bitte nehmen Sie Ihren Schmuck ab.", abbr:"", ja:"アクセサリーを外してください。", note:"MRI・手術・放射線治療前の指示。ピアス・指輪・ネックレス・入れ歯も確認。", example:"Please remove your jewelry and any metal objects before the MRI scan.", cat:"common", level:"basic", dept:"GEN" },
{ en:"I am going to put in a drip.", de:"Ich lege Ihnen jetzt einen Tropf.", abbr:"", ja:"点滴を入れます。", note:"静脈内輸液開始の説明。針を刺す部位・感触・目的を事前に伝える。", example:"I am going to put in a drip to give you fluids and antibiotics.", cat:"common", level:"basic", dept:"GEN" },
{ en:"You need to rest.", de:"Sie müssen sich ausruhen.", abbr:"", ja:"安静にしてください。", note:"活動制限の指示。どの程度の安静か（ベッド安静・室内歩行可など）を具体的に伝える。", example:"You need to rest — please stay in bed until the doctor sees you.", cat:"common", level:"basic", dept:"GEN" },
{ en:"The medication is working.", de:"Das Medikament wirkt.", abbr:"", ja:"薬が効いてきています。", note:"鎮痛薬・降圧薬などの効果発現を患者に伝える表現。経過の共有で安心感を与える。", example:"The medication is working — your blood pressure is coming down nicely.", cat:"common", level:"basic", dept:"GEN" },
{ en:"We are still waiting for the results.", de:"Wir warten noch auf die Ergebnisse.", abbr:"", ja:"まだ結果待ちです。", note:"検査結果の待機中を患者に伝える表現。いつ頃結果が出るかの見込みも伝えると良い。", example:"We are still waiting for the results — it should be about another hour.", cat:"common", level:"basic", dept:"GEN" },
{ en:"The scan was normal.", de:"Die Untersuchung war normal.", abbr:"", ja:"スキャンは異常ありませんでした。", note:"画像検査の正常結果を伝える。患者が安心できる重要な一言。", example:"The scan was normal — there's no sign of a clot or bleed.", cat:"common", level:"basic", dept:"GEN" },
{ en:"We have found something on the scan.", de:"Wir haben etwas auf dem Scan gefunden.", abbr:"", ja:"スキャンで何かが見つかりました。", note:"異常所見の告知前置き。詳細な説明の前に心構えを作ってもらう表現。", example:"We have found something on the scan that needs further investigation.", cat:"common", level:"basic", dept:"GEN" },
{ en:"I will come back to check on you.", de:"Ich komme zurück, um nach Ihnen zu sehen.", abbr:"", ja:"後でまた様子を見に来ます。", note:"患者の不安を軽減する定期的な声かけ。「置き去り」感を防ぐ大切な一言。", example:"I will come back to check on you in about an hour.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Ring the bell if you need anything.", de:"Klingeln Sie, wenn Sie etwas brauchen.", abbr:"", ja:"何かあればナースコールを押してください。", note:"入院患者への基本的な説明。緊急時・疼痛増悪・転倒リスクなど具体的な状況を伝えると良い。", example:"Ring the bell if you need anything or if your pain gets worse.", cat:"common", level:"basic", dept:"GEN" },

// ── リウマチ科 (RHEUM) ──────────────────────────────────────────────
{ en:"Rheumatoid arthritis", de:"Rheumatoide Arthritis", abbr:"RA", ja:"関節リウマチ", note:"滑膜の自己免疫性炎症による慢性関節疾患。RF・抗CCP抗体陽性。関節破壊・変形を来す。早期DMARDs治療が重要。", example:"Rheumatoid arthritis was confirmed by positive anti-CCP antibody and synovitis on MRI.", cat:"diagnosis", level:"basic", dept:"RHEUM" },
{ en:"Systemic lupus erythematosus", de:"Systemischer Lupus erythematodes", abbr:"SLE", ja:"全身性エリテマトーデス", note:"多臓器を侵す自己免疫疾患。若年女性に多い。蝶形紅斑・腎炎・漿膜炎など多彩な症状。抗dsDNA抗体が特異的。", example:"Systemic lupus erythematosus was diagnosed based on the malar rash, arthritis, and positive ANA.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },
{ en:"Sjögren's syndrome", de:"Sjögren-Syndrom", abbr:"SS", ja:"シェーグレン症候群", note:"外分泌腺（涙腺・唾液腺）の自己免疫性炎症。口腔乾燥・眼球乾燥が主症状。抗SS-A/SS-B抗体陽性。", example:"Sjögren's syndrome was suspected due to dry eyes, dry mouth, and positive anti-SS-A antibody.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },
{ en:"Disease activity score 28", de:"Disease-Activity-Score 28", abbr:"DAS28", ja:"疾患活動性スコア28", note:"関節リウマチの疾患活動性指標。28関節の圧痛・腫脹数＋ESR/CRP＋患者全般評価で計算。寛解判定に使用。", example:"DAS28 score was 2.3, indicating remission of rheumatoid arthritis.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },
{ en:"Anti-cyclic citrullinated peptide antibody", de:"Anti-CCP-Antikörper", abbr:"anti-CCP", ja:"抗シトルリン化ペプチド抗体", note:"関節リウマチの特異度95%以上の血清マーカー。発症前から陽性になることがあり早期診断に有用。関節破壊予測にも使用。", example:"Anti-CCP antibody was strongly positive at 120 U/mL, supporting the diagnosis of RA.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },
{ en:"Disease-modifying antirheumatic drug", de:"Krankheitsmodifizierende Antirheumatika", abbr:"DMARD", ja:"疾患修飾性抗リウマチ薬", note:"関節リウマチの疾患進行を抑制する薬剤の総称。メトトレキサートが第一選択。生物学的製剤・JAK阻害薬も含む。", example:"Methotrexate was initiated as the first-line DMARD after confirming the RA diagnosis.", cat:"treatment", level:"intermediate", dept:"RHEUM" },
{ en:"Biological agent", de:"Biologisches Arzneimittel", abbr:"bDMARD", ja:"生物学的製剤", note:"遺伝子工学で作られた分子標的薬。TNF阻害薬・IL-6阻害薬・B細胞除去薬など。従来DMARDs無効例に使用。感染症リスクに注意。", example:"Biological agent with tocilizumab was started after inadequate response to methotrexate.", cat:"treatment", level:"intermediate", dept:"RHEUM" },
{ en:"Synovitis", de:"Synovitis", abbr:"", ja:"滑膜炎", note:"関節滑膜の炎症。関節腫脹・熱感・疼痛を来す。MRI・超音波で評価。関節リウマチ・痛風・反応性関節炎などで生じる。", example:"Synovitis in the wrist joints was confirmed by power Doppler ultrasound.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },
{ en:"Morning stiffness", de:"Morgensteifigkeit", abbr:"", ja:"朝のこわばり", note:"起床後の関節こわばり。関節リウマチでは1時間以上続くことが特徴。変形性関節症では通常30分以内。診断の補助となる。", example:"Morning stiffness lasting more than one hour is a hallmark feature of rheumatoid arthritis.", cat:"symptom", level:"basic", dept:"RHEUM" },
{ en:"Raynaud's phenomenon", de:"Raynaud-Phänomen", abbr:"", ja:"レイノー現象", note:"寒冷・ストレスで手指の血管が攣縮し、蒼白→チアノーゼ→発赤の三相変色を示す。原発性と二次性（膠原病合併）がある。", example:"Raynaud's phenomenon with color changes triggered by cold was the patient's first symptom.", cat:"symptom", level:"intermediate", dept:"RHEUM" },
{ en:"Gout attack", de:"Gichtanfall", abbr:"", ja:"痛風発作", note:"高尿酸血症による尿酸ナトリウム結晶の関節内沈着。第一MTP関節（母趾）の急性炎症が典型的。秋葉（コルヒチン）・NSAIDsで治療。", example:"The gout attack was confirmed by needle-shaped urate crystals in the joint aspirate.", cat:"diagnosis", level:"basic", dept:"RHEUM" },
{ en:"Antinuclear antibody", de:"Antinukleäre Antikörper", abbr:"ANA", ja:"抗核抗体", note:"自己免疫疾患のスクリーニング検査。SLE・混合性結合組織病・強皮症などで陽性。健常者でも低力価陽性あり。", example:"Antinuclear antibody was positive at 1:640 with a homogeneous pattern.", cat:"diagnosis", level:"intermediate", dept:"RHEUM" },

// ── 内分泌・代謝科 (ENDO) ──────────────────────────────────────────
{ en:"Glycated hemoglobin", de:"Glykiertes Hämoglobin", abbr:"HbA1c", ja:"グリコヘモグロビン（HbA1c）", note:"過去1〜2ヶ月の平均血糖を反映。糖尿病診断基準（≥6.5%）・治療目標（<7%）として使用。赤血球寿命に影響される。", example:"HbA1c was 9.2%, indicating poor glycemic control over the past three months.", cat:"diagnosis", level:"basic", dept:"ENDO" },
{ en:"Thyroid-stimulating hormone", de:"Schilddrüsenstimulierendes Hormon", abbr:"TSH", ja:"甲状腺刺激ホルモン", note:"下垂体前葉から分泌。甲状腺機能評価の第一検査。低値→甲状腺機能亢進症、高値→甲状腺機能低下症を示唆。", example:"TSH was suppressed at 0.01 mIU/L, consistent with hyperthyroidism.", cat:"diagnosis", level:"basic", dept:"ENDO" },
{ en:"Diabetic ketoacidosis", de:"Diabetische Ketoazidose", abbr:"DKA", ja:"糖尿病性ケトアシドーシス", note:"インスリン欠乏による高血糖・ケトン体産生・代謝性アシドーシスの三徴。1型糖尿病の急性合併症。輸液・インスリン静注で治療。", example:"Diabetic ketoacidosis was managed with IV fluids, insulin infusion, and potassium replacement.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Hyperosmolar hyperglycemic state", de:"Hyperosmolares hyperglykämisches Syndrom", abbr:"HHS", ja:"高浸透圧高血糖症候群", note:"2型糖尿病で高度高血糖（>600mg/dL）・脱水・高浸透圧による意識障害。ケトアシドーシスは軽度。輸液が最重要治療。", example:"Hyperosmolar hyperglycemic state was suspected with blood glucose of 850 mg/dL and altered consciousness.", cat:"diagnosis", level:"advanced", dept:"ENDO" },
{ en:"Graves' disease", de:"Morbus Basedow", abbr:"", ja:"バセドウ病（グレーブス病）", note:"TSH受容体抗体による甲状腺機能亢進症。眼球突出・びまん性甲状腺腫・頻脈の三徴。抗甲状腺薬・放射性ヨード・手術で治療。", example:"Graves' disease was confirmed by elevated free T4, suppressed TSH, and positive TRAb.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Hashimoto's thyroiditis", de:"Hashimoto-Thyreoiditis", abbr:"", ja:"橋本病（慢性甲状腺炎）", note:"甲状腺への自己免疫性炎症による慢性甲状腺炎。女性に多い。抗TPO抗体陽性。甲状腺機能低下症に進行することが多い。", example:"Hashimoto's thyroiditis was confirmed by elevated anti-TPO antibody and characteristic ultrasound findings.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Cushing's syndrome", de:"Cushing-Syndrom", abbr:"", ja:"クッシング症候群", note:"コルチゾール過剰による症候群。中心性肥満・月状顔貌・紫色皮膚線条が特徴的。副腎腫瘍・下垂体腫瘍・外因性ステロイドが原因。", example:"Cushing's syndrome was suspected due to central obesity, hypertension, and elevated 24-hour urinary cortisol.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Primary hyperaldosteronism", de:"Primärer Hyperaldosteronismus", abbr:"PA", ja:"原発性アルドステロン症", note:"副腎からのアルドステロン過剰分泌による高血圧・低カリウム血症。二次性高血圧の最多原因。副腎腺腫・両側過形成が主な原因。", example:"Primary hyperaldosteronism was confirmed by elevated aldosterone-to-renin ratio and adrenal CT.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Pheochromocytoma", de:"Phäochromozytom", abbr:"", ja:"褐色細胞腫", note:"副腎髄質のカテコラミン産生腫瘍。発作性高血圧・頭痛・発汗・動悸の四徴。尿中カテコラミン測定・CT/MRI・MIBGシンチで診断。", example:"Pheochromocytoma was suspected after recurrent hypertensive crises with headache and sweating.", cat:"diagnosis", level:"advanced", dept:"ENDO" },
{ en:"Hypoglycemia", de:"Hypoglykämie", abbr:"", ja:"低血糖", note:"血糖<70mg/dL。発汗・動悸・手の震えの交感神経症状→意識障害・痙攣。インスリン過剰・食事不足が原因。ブドウ糖補充で即時対処。", example:"Hypoglycemia with blood glucose of 42 mg/dL was treated with oral glucose tablets.", cat:"diagnosis", level:"basic", dept:"ENDO" },
{ en:"Insulin resistance", de:"Insulinresistenz", abbr:"IR", ja:"インスリン抵抗性", note:"インスリンに対する組織の反応性低下。2型糖尿病・メタボリックシンドロームの基盤。肥満・運動不足・睡眠障害が悪化因子。", example:"Insulin resistance was evident from the elevated fasting insulin and HOMA-IR score.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },

// ── 腎臓内科 (NEPH) ─────────────────────────────────────────────────
{ en:"Estimated glomerular filtration rate", de:"Geschätzte glomeruläre Filtrationsrate", abbr:"eGFR", ja:"推算糸球体濾過量", note:"腎機能の指標。血清クレアチニン・年齢・性別から計算。CKD病期分類に使用。60未満でCKD疑い。", example:"eGFR was 28 mL/min/1.73m², indicating CKD stage G4.", cat:"diagnosis", level:"basic", dept:"NEPH" },
{ en:"Proteinuria", de:"Proteinurie", abbr:"", ja:"蛋白尿", note:"尿中への蛋白漏出。腎糸球体・尿細管障害の指標。30〜300mg/gCrをアルブミン尿、>300mg/gCrを顕性蛋白尿と分類。CKD進行の独立危険因子。", example:"Proteinuria of 2.5 g/day was detected on 24-hour urine collection.", cat:"diagnosis", level:"basic", dept:"NEPH" },
{ en:"Acute kidney injury", de:"Akute Nierenschädigung", abbr:"AKI", ja:"急性腎障害", note:"48時間以内の血清Cr≥0.3mg/dL上昇またはUO<0.5mL/kg/h（>6時間）で定義。前腎性・腎性・後腎性に分類。早期原因同定と治療が重要。", example:"Acute kidney injury was diagnosed after creatinine rose from 0.9 to 2.4 mg/dL within 24 hours.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Chronic kidney disease", de:"Chronische Nierenerkrankung", abbr:"CKD", ja:"慢性腎臓病", note:"3ヶ月以上持続する腎障害（蛋白尿・画像異常など）またはeGFR<60。G1〜G5の5段階に分類。透析・移植への進行予防が目標。", example:"Chronic kidney disease stage G3b was managed with ACE inhibitor and dietary protein restriction.", cat:"diagnosis", level:"basic", dept:"NEPH" },
{ en:"Hemodialysis", de:"Hämodialyse", abbr:"HD", ja:"血液透析", note:"体外循環で血液を人工腎臓に通し老廃物・水分を除去。週3回・1回4時間が標準。シャント作成・抗凝固薬が必要。", example:"Hemodialysis was initiated via a tunneled catheter while awaiting AV fistula maturation.", cat:"treatment", level:"intermediate", dept:"NEPH" },
{ en:"Peritoneal dialysis", de:"Peritonealdialyse", abbr:"PD", ja:"腹膜透析", note:"腹膜をフィルターとして利用する在宅透析。持続携行式（CAPD）・自動腹膜透析（APD）がある。残腎機能保持・生活の質に優れる。", example:"Peritoneal dialysis was chosen for the working patient due to its flexibility and home-based nature.", cat:"treatment", level:"intermediate", dept:"NEPH" },
{ en:"Renal biopsy", de:"Nierenbiopsie", abbr:"", ja:"腎生検", note:"腎臓から組織を採取して病理診断を行う検査。ネフローゼ症候群・糸球体腎炎・移植腎拒絶反応の診断に必須。出血リスクに注意。", example:"Renal biopsy revealed IgA nephropathy with focal segmental glomerulosclerosis.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Nephrotic syndrome", de:"Nephrotisches Syndrom", abbr:"", ja:"ネフローゼ症候群", note:"大量蛋白尿（>3.5g/日）・低アルブミン血症・浮腫・高脂血症の四徴。微小変化型・膜性腎症・FSGS等が原因。ステロイドが主体の治療。", example:"Nephrotic syndrome with massive proteinuria and bilateral leg edema was managed with prednisolone.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Glomerulonephritis", de:"Glomerulonephritis", abbr:"GN", ja:"糸球体腎炎", note:"糸球体の炎症性疾患。血尿・蛋白尿・高血圧・腎機能低下を来す。IgA腎症が最多。病型により免疫抑制療法の適応が異なる。", example:"Glomerulonephritis was confirmed by renal biopsy showing mesangial IgA deposits.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Hyperkalemia", de:"Hyperkaliämie", abbr:"", ja:"高カリウム血症", note:"血清K>5.5mEq/L。腎不全・ACE阻害薬・K保持性利尿薬などで発生。心筋の興奮性異常→致死的不整脈リスク。緊急時はカルシウム製剤・インスリン＋ブドウ糖で対処。", example:"Hyperkalemia at 6.8 mEq/L was treated with calcium gluconate and insulin-dextrose infusion.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Renal replacement therapy", de:"Nierenersatztherapie", abbr:"RRT", ja:"腎代替療法", note:"末期腎不全（ESKD）または急性腎障害（AKI）に対する腎機能代替治療。血液透析・腹膜透析・腎移植の3種類がある。", example:"Renal replacement therapy options were discussed with the patient as eGFR declined below 15.", cat:"treatment", level:"intermediate", dept:"NEPH" },

// ── 血液内科 (HEME) ──────────────────────────────────────────────────
{ en:"Acute myeloid leukemia", de:"Akute myeloische Leukämie", abbr:"AML", ja:"急性骨髄性白血病", note:"骨髄系造血幹細胞の悪性腫瘍。骨髄芽球≥20%で診断。発熱・出血・貧血を来す。化学療法・同種造血幹細胞移植が治療の中心。", example:"Acute myeloid leukemia with FLT3 mutation was treated with standard 7+3 induction chemotherapy.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Diffuse large B-cell lymphoma", de:"Diffuses großzelliges B-Zell-Lymphom", abbr:"DLBCL", ja:"びまん性大細胞型B細胞リンパ腫", note:"最も多い非ホジキンリンパ腫。リンパ節腫脹・B症状（発熱・夜間発汗・体重減少）を来す。R-CHOP療法が標準治療。", example:"Diffuse large B-cell lymphoma was staged as IIE with R-CHOP chemotherapy planned.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Bone marrow biopsy", de:"Knochenmarkbiopsie", abbr:"BMBx", ja:"骨髄生検", note:"腸骨稜から骨髄組織を採取する検査。白血病・リンパ腫・MDS・骨髄腫の診断・病期分類に必須。穿刺吸引（骨髄穿刺）と組み合わせて施行。", example:"Bone marrow biopsy confirmed hypercellular marrow with 35% blasts consistent with AML.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Disseminated intravascular coagulation", de:"Disseminierte intravasale Gerinnung", abbr:"DIC", ja:"播種性血管内凝固症候群", note:"全身性の過凝固と線溶亢進が同時進行する致命的状態。敗血症・産科合併症・悪性腫瘍が原因。PT・APTT延長・FDP上昇・フィブリノゲン低下。", example:"DIC was confirmed by elevated FDP, prolonged PT, and falling fibrinogen in the septic patient.", cat:"diagnosis", level:"advanced", dept:"HEME" },
{ en:"Hematopoietic stem cell transplantation", de:"Hämatopoetische Stammzelltransplantation", abbr:"HSCT", ja:"造血幹細胞移植", note:"大量化学放射線療法後に造血幹細胞を移植して造血を再建する治療。自己（自家）と同種がある。白血病・リンパ腫・再生不良性貧血が主な適応。", example:"Allogeneic HSCT from an HLA-matched sibling was planned after the second remission.", cat:"treatment", level:"advanced", dept:"HEME" },
{ en:"Graft-versus-host disease", de:"Graft-versus-Host-Erkrankung", abbr:"GVHD", ja:"移植片対宿主病", note:"同種移植後にドナーT細胞がレシピエント臓器を攻撃する合併症。急性（100日以内）/ 慢性に分類。皮膚・肝・消化管が標的臓器。ステロイドが治療の主体。", example:"Graft-versus-host disease with skin rash and elevated bilirubin developed on day 25 post-transplant.", cat:"diagnosis", level:"advanced", dept:"HEME" },
{ en:"Iron deficiency anemia", de:"Eisenmangelanämie", abbr:"IDA", ja:"鉄欠乏性貧血", note:"体内鉄の欠乏による小球性低色素性貧血。最多の貧血原因。血清フェリチン低値・TIBC高値。原因検索（消化管出血・月経過多）と鉄補充が治療。", example:"Iron deficiency anemia was treated with oral ferrous sulfate after colonoscopy ruled out bleeding.", cat:"diagnosis", level:"basic", dept:"HEME" },
{ en:"International normalized ratio", de:"Internationale normalisierte Ratio", abbr:"INR", ja:"国際標準化比（INR）", note:"プロトロンビン時間の国際標準化。ワルファリン治療モニタリングに使用。心房細動・静脈血栓症では2.0〜3.0を目標値とする。", example:"INR was 3.8, above the therapeutic range, so warfarin was held for one dose.", cat:"diagnosis", level:"basic", dept:"HEME" },
{ en:"Myelodysplastic syndrome", de:"Myelodysplastisches Syndrom", abbr:"MDS", ja:"骨髄異形成症候群", note:"造血幹細胞の異形成による骨髄機能不全・AML転化リスクのある疾患群。血球減少・形態異常が特徴。支持療法・低メチル化薬・移植が治療選択肢。", example:"Myelodysplastic syndrome with excess blasts was treated with azacitidine.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Multiple myeloma", de:"Multiples Myelom", abbr:"MM", ja:"多発性骨髄腫", note:"骨髄内の形質細胞が腫瘍性増殖する血液悪性腫瘍。CRAB症状（高カルシウム血症・腎障害・貧血・骨病変）が特徴的。免疫固定法でMタンパク検出。", example:"Multiple myeloma presenting with back pain was confirmed by 40% plasma cells on bone marrow biopsy.", cat:"diagnosis", level:"intermediate", dept:"HEME" },

// ── 腫瘍内科 (ONCO) ──────────────────────────────────────────────────
{ en:"TNM staging", de:"TNM-Klassifikation", abbr:"TNM", ja:"TNM病期分類", note:"腫瘍の広がりを原発腫瘍（T）・所属リンパ節（N）・遠隔転移（M）で分類するシステム。UICC/AJCC準拠。治療方針・予後判断の基本。", example:"TNM staging revealed T2N1M0, corresponding to stage IIB non-small cell lung cancer.", cat:"diagnosis", level:"intermediate", dept:"ONCO" },
{ en:"Performance status", de:"Leistungsstatus", abbr:"PS", ja:"パフォーマンスステータス", note:"患者の全身状態・日常生活動作の指標。ECOGスコア0〜4で評価。化学療法の適応・用量決定に重要。PS≥3では積極的治療の適応を慎重に検討。", example:"Performance status was ECOG 1, allowing full-dose chemotherapy to proceed.", cat:"diagnosis", level:"basic", dept:"ONCO" },
{ en:"Immune checkpoint inhibitor", de:"Immun-Checkpoint-Inhibitor", abbr:"ICI", ja:"免疫チェックポイント阻害薬", note:"PD-1・PD-L1・CTLA-4を標的とする免疫療法薬。T細胞の抗腫瘍免疫を賦活化。肺癌・メラノーマ・腎癌など多くの癌腫に適応。免疫関連有害事象（irAE）に注意。", example:"Immune checkpoint inhibitor with pembrolizumab was initiated for PD-L1-positive NSCLC.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Tumor mutational burden", de:"Tumormutationslast", abbr:"TMB", ja:"腫瘍遺伝子変異量", note:"腫瘍ゲノム内の体細胞変異の総数。TMB高値は免疫チェックポイント阻害薬の治療効果予測バイオマーカー。次世代シークエンスで測定。", example:"Tumor mutational burden was high at 18 mutations/Mb, suggesting benefit from immunotherapy.", cat:"diagnosis", level:"advanced", dept:"ONCO" },
{ en:"Febrile neutropenia", de:"Febrile Neutropenie", abbr:"FN", ja:"発熱性好中球減少症", note:"好中球数<500/μL（または<1000かつ減少予測）に発熱（≥38.3℃）を合併した状態。化学療法の致命的合併症。広域抗菌薬（β-ラクタム系）の速やかな投与が必要。", example:"Febrile neutropenia on day 10 of CHOP chemotherapy was treated empirically with piperacillin-tazobactam.", cat:"diagnosis", level:"intermediate", dept:"ONCO" },
{ en:"RECIST criteria", de:"RECIST-Kriterien", abbr:"RECIST", ja:"固形がん治療効果判定基準", note:"固形腫瘍の化学療法効果を画像で判定する基準。CR（完全消失）・PR（>30%縮小）・SD（不変）・PD（>20%増大）に分類。", example:"Response assessment by RECIST showed partial response with 45% decrease in tumor size.", cat:"diagnosis", level:"intermediate", dept:"ONCO" },
{ en:"Tumor marker", de:"Tumormarker", abbr:"", ja:"腫瘍マーカー", note:"悪性腫瘍が産生する物質を血中測定。CEA（大腸癌）・AFP（肝細胞癌）・PSA（前立腺癌）・CA125（卵巣癌）など。スクリーニングより経過観察・再発検出に有用。", example:"Tumor marker CA125 fell from 850 to 42 U/mL after three cycles of carboplatin-paclitaxel.", cat:"diagnosis", level:"basic", dept:"ONCO" },
{ en:"Palliative care referral", de:"Palliativmedizinische Überweisung", abbr:"", ja:"緩和ケア紹介", note:"疾患の段階を問わず疼痛・倦怠感・心理的苦痛の緩和を目的とした専門チームへの紹介。早期からの緩和ケア介入がQOL・予後を改善するとのエビデンスあり。", example:"Palliative care referral was made early to address pain and psychosocial needs alongside chemotherapy.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Cancer-related fatigue", de:"Tumorbedingte Fatigue", abbr:"CRF", ja:"がん関連疲労", note:"がん・その治療に伴う身体的・精神的・認知的疲労感。最も多い症状。貧血・甲状腺機能低下・抑うつなど可逆的原因の検索と運動療法が有効。", example:"Cancer-related fatigue was assessed using the Brief Fatigue Inventory and managed with an exercise program.", cat:"symptom", level:"intermediate", dept:"ONCO" },
{ en:"Targeted therapy", de:"Gezielte Therapie", abbr:"", ja:"分子標的療法", note:"腫瘍細胞に特異的な分子（遺伝子変異・過剰発現受容体）を標的とする治療薬。EGFR阻害薬・HER2阻害薬・BCR-ABL阻害薬など。遺伝子検査で適応判断。", example:"Targeted therapy with osimertinib was selected based on EGFR exon 19 deletion mutation.", cat:"treatment", level:"intermediate", dept:"ONCO" },

// ── 感染症内科 (INFECT) ───────────────────────────────────────────────
{ en:"Methicillin-resistant Staphylococcus aureus", de:"Methicillinresistenter Staphylococcus aureus", abbr:"MRSA", ja:"メチシリン耐性黄色ブドウ球菌", note:"βラクタム系抗菌薬に耐性を持つ黄色ブドウ球菌。市中・院内感染の重要な起因菌。バンコマイシン・ダプトマイシンが治療薬。接触予防策が必要。", example:"MRSA bacteremia was confirmed, and vancomycin therapy was initiated with trough monitoring.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"Antibiotic stewardship program", de:"Antibiotikastewardship-Programm", abbr:"ASP", ja:"抗菌薬適正使用支援プログラム", note:"抗菌薬の適正使用・耐性菌抑制・医療費削減を目的とした多職種チームによる取り組み。処方レビュー・de-escalation・教育が主な活動内容。", example:"The antibiotic stewardship program recommended de-escalating from meropenem to ampicillin-sulbactam.", cat:"common", level:"intermediate", dept:"INFECT" },
{ en:"Empiric antibiotic therapy", de:"Empirische Antibiotikatherapie", abbr:"", ja:"経験的抗菌薬治療", note:"培養結果判明前に、臨床所見・患者背景・予想起因菌に基づいて開始する抗菌薬治療。結果判明後に感受性に基づきde-escalationする。", example:"Empiric antibiotic therapy with piperacillin-tazobactam was started pending blood culture results.", cat:"treatment", level:"intermediate", dept:"INFECT" },
{ en:"Minimum inhibitory concentration", de:"Minimale Hemmkonzentration", abbr:"MIC", ja:"最小発育阻止濃度", note:"細菌の増殖を完全に抑制する最低濃度。PK/PD（薬物動態/薬力学）パラメータで治療効果予測・用量設定に使用。MIC高値は耐性を示唆。", example:"MIC of 2 μg/mL for vancomycin against MRSA required higher dosing to achieve target AUC/MIC.", cat:"diagnosis", level:"advanced", dept:"INFECT" },
{ en:"Blood culture", de:"Blutkultur", abbr:"BC", ja:"血液培養", note:"菌血症・敗血症の診断のための血液検査。異なる部位から2セット採取が基本。抗菌薬投与前に採取することが重要。陽性率向上には適切な採血量（各10mL）が必要。", example:"Two sets of blood cultures were drawn before starting antibiotics for the febrile patient.", cat:"diagnosis", level:"basic", dept:"INFECT" },
{ en:"HIV viral load", de:"HIV-Viruslast", abbr:"VL", ja:"HIV ウイルス量", note:"血中のHIV RNA量をコピー数/mLで表す。治療効果モニタリングに使用。目標は検出限界以下（<50copies/mL）。ウイルス量増加は耐性・アドヒアランス低下を示唆。", example:"HIV viral load was undetectable after 6 months of antiretroviral therapy.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"Opportunistic infection", de:"Opportunistische Infektion", abbr:"OI", ja:"日和見感染症", note:"健常者ではほぼ発症しない微生物がCD4低下などの免疫不全状態に感染する疾患。PCP・CMV網膜炎・クリプトコッカス髄膜炎など。HIV感染のAIDS定義疾患を含む。", example:"Opportunistic infection with Pneumocystis jirovecii pneumonia occurred at CD4 count of 38 cells/μL.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"Carbapenem-resistant Enterobacterales", de:"Carbapenemresistente Enterobacterales", abbr:"CRE", ja:"カルバペネム耐性腸内細菌科細菌", note:"カルバペネム系抗菌薬に耐性を示す腸内細菌科細菌。KPC・NDM・OXA-48などのカルバペネマーゼを産生。治療選択肢が極めて限られ、コリスチン・セフタジジム/アビバクタムを使用。", example:"CRE bloodstream infection required combination therapy with ceftazidime-avibactam.", cat:"diagnosis", level:"advanced", dept:"INFECT" },
{ en:"Clostridioides difficile infection", de:"Clostridioides-difficile-Infektion", abbr:"CDI", ja:"クロストリジオイデス・ディフィシル感染症", note:"抗菌薬投与後の腸内菌叢破綻により発症する下痢・大腸炎。毒素A・Bによる腸管障害。バンコマイシン経口・フィダキソマイシンで治療。再発リスクに注意。", example:"Clostridioides difficile infection was confirmed by positive toxin PCR and treated with oral vancomycin.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"Infection control precautions", de:"Infektionskontrollmaßnahmen", abbr:"", ja:"感染対策予防措置", note:"病原体の伝播を防ぐための対策。標準予防策（全患者）＋感染経路別予防策（接触・飛沫・空気感染）を組み合わせる。個人防護具（PPE）の適切な使用が重要。", example:"Contact and droplet precautions were implemented for the patient with suspected influenza.", cat:"common", level:"basic", dept:"INFECT" },

// ── 消化器内科・追加 (GI) ─────────────────────────────────────────────
{ en:"Hepatic encephalopathy", de:"Hepatische Enzephalopathie", abbr:"HE", ja:"肝性脳症", note:"肝機能不全による高アンモニア血症が引き起こす神経・精神障害。傾眠・羽ばたき振戦・見当識障害を来す。ラクツロース・リファキシミンで治療。", example:"Hepatic encephalopathy grade III was treated with lactulose titrated to two soft stools per day.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Esophageal variceal bleeding", de:"Ösophagusvarizenblutung", abbr:"EVB", ja:"食道静脈瘤出血", note:"肝硬変による門脈圧亢進症に伴う食道静脈瘤破裂出血。大量吐血→出血性ショック。緊急内視鏡的静脈瘤結紮術（EVL）が第一選択。オクトレオチド投与も行う。", example:"Esophageal variceal bleeding was controlled with emergency EVL and octreotide infusion.", cat:"diagnosis", level:"advanced", dept:"GI" },
{ en:"Spontaneous bacterial peritonitis", de:"Spontane bakterielle Peritonitis", abbr:"SBP", ja:"特発性細菌性腹膜炎", note:"腹水を伴う肝硬変に合併する腹水感染。多形核球>250/μLで診断。発熱・腹痛・意識変容。セフォタキシムが第一選択。再発予防にノルフロキサシン長期投与。", example:"Spontaneous bacterial peritonitis was confirmed by PMN count of 380 cells/μL in ascitic fluid.", cat:"diagnosis", level:"advanced", dept:"GI" },
{ en:"Endoscopic mucosal resection", de:"Endoskopische Mukosaresektion", abbr:"EMR", ja:"内視鏡的粘膜切除術", note:"消化管の表在性腫瘍を内視鏡下に切除する低侵襲手術。粘膜下層への局注後に切除。早期胃癌・大腸ポリープの標準治療。2cm以上の病変にはESDを考慮。", example:"EMR successfully removed a 1.5 cm flat adenoma in the ascending colon.", cat:"treatment", level:"intermediate", dept:"GI" },
{ en:"Fecal calprotectin", de:"Fäkales Calprotectin", abbr:"FC", ja:"便中カルプロテクチン", note:"腸管炎症のバイオマーカー。炎症性腸疾患（IBD）の活動性評価・再燃検出に使用。>200μg/gで腸管炎症を示唆。大腸内視鏡の代替としての役割も注目。", example:"Fecal calprotectin was elevated at 850 μg/g, prompting colonoscopy to assess IBD activity.", cat:"diagnosis", level:"intermediate", dept:"GI" },

// ── 一般内科・追加フレーズ (GEN) ─────────────────────────────────────
{ en:"Let me examine you.", de:"Ich untersuche Sie jetzt.", abbr:"", ja:"診察させてください。", note:"診察開始前の声かけ。これから何をするかを伝えることで患者の不安を軽減できる。", example:"Let me examine you — I'll start with your heart and lungs.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Does it radiate anywhere?", de:"Strahlt der Schmerz irgendwohin aus?", abbr:"", ja:"痛みはどこかに広がりますか？", note:"放散痛の有無を確認する問診表現。心筋梗塞（左肩・顎）・胆嚢炎（右肩）など特徴的な放散パターンが診断に役立つ。", example:"Does it radiate anywhere — down your arm or up to your jaw?", cat:"common", level:"basic", dept:"GEN" },
{ en:"What makes it better or worse?", de:"Was lindert oder verschlimmert es?", abbr:"", ja:"何をすると良くなりますか、または悪くなりますか？", note:"症状増悪・寛解因子の問診。運動・食事・体位・呼吸などとの関連を確認する。OPQRST問診の一部。", example:"What makes it better or worse — does eating or bending forward change it?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Have you noticed any blood in your urine?", de:"Haben Sie Blut im Urin bemerkt?", abbr:"", ja:"尿に血が混じっていましたか？", note:"血尿（肉眼的・顕微鏡的）の有無を問診。泌尿器科疾患（腫瘍・結石・感染）・腎疾患の重要な症状。色（鮮血・コーラ色）・タイミングも確認。", example:"Have you noticed any blood in your urine, or has it appeared dark or cola-colored?", cat:"common", level:"basic", dept:"GEN" },
{ en:"Have you had any recent travel?", de:"Haben Sie kürzlich eine Reise unternommen?", abbr:"", ja:"最近、旅行しましたか？", note:"感染症・渡航歴の問診。マラリア・腸チフス・デング熱などの渡航関連感染症の疑い時に必須。どこへ・いつ・何をしたかを具体的に確認。", example:"Have you had any recent travel abroad, particularly to tropical regions?", cat:"common", level:"basic", dept:"GEN" },
{ en:"I need to refer you to a specialist.", de:"Ich muss Sie an einen Spezialisten überweisen.", abbr:"", ja:"専門医に紹介する必要があります。", note:"専門科への紹介を伝える表現。理由を簡潔に説明し、受診の目的と流れを患者に伝えることが重要。", example:"I need to refer you to a specialist — a cardiologist who can assess your heart in more detail.", cat:"common", level:"basic", dept:"GEN" },
{ en:"We will need to monitor this closely.", de:"Wir müssen das engmaschig beobachten.", abbr:"", ja:"これは注意深く経過観察する必要があります。", note:"慎重な経過観察が必要な患者への説明。具体的にいつ・何を監視するかを伝えることで患者の理解と協力を得やすい。", example:"We will need to monitor this closely with repeat blood tests in two weeks.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Your test results have come back.", de:"Ihre Testergebnisse liegen vor.", abbr:"", ja:"検査結果が出ました。", note:"検査結果を伝える前置き表現。良い結果・悪い結果に関わらず、落ち着いた口調で患者に結果を伝える準備をする。", example:"Your test results have come back, and I'd like to discuss them with you.", cat:"common", level:"basic", dept:"GEN" },
{ en:"I want to take a swab.", de:"Ich möchte einen Abstrich machen.", abbr:"", ja:"スワブ（ぬぐい液）を採取します。", note:"鼻腔・咽頭・傷口などからの検体採取を説明する表現。感染症の診断に用いる。少し不快感があることを事前に伝える。", example:"I want to take a swab from your throat to check for infection.", cat:"common", level:"basic", dept:"GEN" },
{ en:"Take a deep breath for me.", de:"Atmen Sie bitte tief für mich ein.", abbr:"", ja:"深呼吸してください。", note:"聴診・呼吸機能検査時の指示。ゆっくりと大きく息を吸い込むよう伝える。患者が正しく行えているか確認する。", example:"Take a deep breath for me — in through your nose and out through your mouth.", cat:"common", level:"basic", dept:"GEN" },

// ── 解剖学：骨（頭蓋・脊椎） ──────────────────────────────────────────
{ en:"Frontal bone", de:"Stirnbein", abbr:"", ja:"前頭骨", note:"頭蓋冠前部を形成する骨。前頭洞を内包。眼窩上縁を構成する。骨折時に前頭洞・眼窩への影響を確認。", example:"A frontal bone fracture was identified on CT scan following the forehead impact.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Parietal bone", de:"Scheitelbein", abbr:"", ja:"頭頂骨", note:"頭蓋冠の大部分を占める一対の骨。矢状縫合・冠状縫合・ラムダ縫合に接する。硬膜外血腫が生じやすい中硬膜動脈走行部位に注意。", example:"A parietal bone fracture on the left was associated with an epidural hematoma.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Temporal bone", de:"Schläfenbein", abbr:"", ja:"側頭骨", note:"頭蓋底・側頭部を形成。内耳・中耳・乳様突起・茎状突起を含む。顔面神経・内耳神経が通る。錐体骨折で難聴・顔面神経麻痺を来す。", example:"Temporal bone fracture caused sensorineural hearing loss and facial nerve palsy.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Occipital bone", de:"Hinterhauptbein", abbr:"", ja:"後頭骨", note:"頭蓋後下部を形成。大後頭孔（脳幹・脊髄移行部）を有する。後頭顆で環椎と関節を形成。後頭葉の保護に関与。", example:"Occipital bone fracture extended to the foramen magnum on CT imaging.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Sphenoid bone", de:"Keilbein", abbr:"", ja:"蝶形骨", note:"頭蓋底中央部のバタフライ状の骨。トルコ鞍（下垂体を収容）・蝶形骨洞・視神経管を含む。多くの脳神経・血管が通過する重要な骨。", example:"A sphenoid bone fracture was found at the skull base, raising concern for carotid injury.", cat:"anatomy", level:"advanced", dept:"GEN" },
{ en:"Ethmoid bone", de:"Siebbein", abbr:"", ja:"篩骨", note:"鼻腔上部・眼窩内壁を形成する軽量な骨。篩板に嗅神経線維が通過する多数の小孔がある。頭部外傷で篩板骨折→脳脊髄液鼻漏のリスク。", example:"Ethmoid bone fracture resulted in CSF rhinorrhea confirmed by beta-2 transferrin test.", cat:"anatomy", level:"advanced", dept:"GEN" },
{ en:"Mandible", de:"Unterkiefer", abbr:"", ja:"下顎骨", note:"顔面下部の唯一の可動骨。顎関節（TMJ）を形成。骨折は正中・傍正中・角部・顆部に多い。下歯槽神経の走行に注意。", example:"Mandible fracture at the symphysis required open reduction and internal fixation.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Atlas (C1)", de:"Atlas (C1)", abbr:"C1", ja:"環椎（第1頸椎）", note:"頭蓋骨を支える第1頸椎。椎体がなく前後弓・側塊で構成される輪状の骨。歯突起（軸椎）との関節で頭部の屈曲・回転を担う。", example:"Jefferson fracture of the atlas was managed with a hard cervical collar.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Axis (C2)", de:"Axis (C2)", abbr:"C2", ja:"軸椎（第2頸椎）", note:"第2頸椎。特徴的な歯突起（dens）を持ち環椎との軸関節で首の回旋を担う。歯突起骨折（ハングマン骨折）は頸髄損傷のリスクが高い。", example:"Odontoid fracture of the axis was classified as type II, requiring surgical stabilization.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Cervical vertebrae", de:"Halswirbel", abbr:"C1–C7", ja:"頸椎", note:"7個の頸椎（C1〜C7）。椎骨動脈が横突孔を通る。頸髄を保護する。鞭打ち・ダイビング事故などで骨折・脱臼→四肢麻痺リスク。", example:"Cervical vertebrae alignment was assessed on lateral X-ray after the motor vehicle accident.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Thoracic vertebrae", de:"Brustwirbel", abbr:"T1–T12", ja:"胸椎", note:"12個の胸椎（T1〜T12）。肋骨との関節（肋椎関節）を持つ。後弯（キーフォシス）が正常カーブ。圧迫骨折は骨粗鬆症の高齢者に多い。", example:"Thoracic vertebrae compression fractures at T8 were treated conservatively with a TLSO brace.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Lumbar vertebrae", de:"Lendenwirbel", abbr:"L1–L5", ja:"腰椎", note:"5個の腰椎（L1〜L5）。最も大きな椎骨。前弯（ロードシス）が正常カーブ。腰椎椎間板ヘルニア・脊柱管狭窄症の好発部位（L4/5・L5/S1）。", example:"Lumbar vertebrae MRI revealed disc herniation at L4-L5 compressing the left nerve root.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Sacrum", de:"Kreuzbein", abbr:"", ja:"仙骨", note:"5個の仙椎が癒合した三角形の骨。骨盤後壁を形成。腸骨との仙腸関節を構成。仙骨神経叢（坐骨神経）の起始。", example:"Sacrum fracture was identified on pelvic CT following a high-energy fall.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Coccyx", de:"Steißbein", abbr:"", ja:"尾骨", note:"3〜5個の退化した尾椎が癒合した小骨。転倒・出産時に骨折することがある。多くは保存療法（クッション・鎮痛薬）で対処。", example:"Coccyx fracture after a fall was managed with a coccyx cushion and analgesics.", cat:"anatomy", level:"basic", dept:"GEN" },

// ── 解剖学：骨（上肢） ────────────────────────────────────────────────
{ en:"Clavicle", de:"Schlüsselbein", abbr:"", ja:"鎖骨", note:"肩と胸骨をつなぐS字状の長骨。転倒で骨折頻度が高い（全骨折の5%）。中1/3骨折が最多。胸鎖関節・肩鎖関節を形成。", example:"Clavicle fracture in the middle third was treated with a figure-of-eight bandage.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Scapula", de:"Schulterblatt", abbr:"", ja:"肩甲骨", note:"背部の三角形の扁平骨。肩甲棘・烏口突起・関節窩を持つ。上腕骨頭との肩関節を形成。肩甲骨骨折は高エネルギー外傷に多い。", example:"Scapula fracture was associated with ipsilateral pneumothorax and rib fractures.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Humerus", de:"Oberarmknochen", abbr:"", ja:"上腕骨", note:"上肢の長骨。近位（肩関節）・遠位（肘関節）に関節を持つ。外科頸骨折（高齢者の転倒）・顆上骨折（小児）が多い。橈骨神経の走行に注意。", example:"Humerus shaft fracture caused wrist drop due to radial nerve injury.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Radius", de:"Speiche", abbr:"", ja:"橈骨", note:"前腕の橈側（母指側）の長骨。遠位橈骨骨折（コーレス骨折）は最も多い骨折のひとつ。回内・回外運動の軸となる骨。", example:"Distal radius fracture (Colles' type) was reduced and immobilized with a plaster cast.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Ulna", de:"Elle", abbr:"", ja:"尺骨", note:"前腕の尺側（小指側）の長骨。肘頭（olecranon）で肘関節を形成する。尺骨神経が内側を走行し、骨折で小指側のしびれを来す。", example:"Ulna shaft fracture with radial head dislocation is classified as a Monteggia fracture.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Carpal bones", de:"Handwurzelknochen", abbr:"", ja:"手根骨", note:"8個の手根骨（近位列：舟状骨・月状骨・三角骨・豆状骨、遠位列：大菱形骨・小菱形骨・有頭骨・有鈎骨）。転倒で舟状骨骨折が多く、疼痛持続時はCT・MRIで確認。", example:"Carpal bones X-ray was normal, but scaphoid fracture was confirmed on MRI.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Metacarpal bones", de:"Mittelhandknochen", abbr:"", ja:"中手骨", note:"5本の中手骨（MC1〜MC5）。第5中手骨頸部骨折（ボクサー骨折）は握り拳での殴打で生じる。第1中手骨基部骨折（ベネット骨折）は母指骨折として重要。", example:"Fifth metacarpal neck fracture (boxer's fracture) was splinted in the intrinsic-plus position.", cat:"anatomy", level:"intermediate", dept:"GEN" },

// ── 解剖学：骨（下肢） ────────────────────────────────────────────────
{ en:"Pelvis", de:"Becken", abbr:"", ja:"骨盤", note:"左右の寛骨（腸骨・坐骨・恥骨）と仙骨・尾骨からなる輪状の骨格。体重を下肢に伝達。骨盤骨折は大量出血リスクあり。女性では出産に関与。", example:"Pelvis fracture with open-book pattern required pelvic binder and angiographic embolization.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Femur", de:"Oberschenkelknochen", abbr:"", ja:"大腿骨", note:"人体最長・最強の長骨。大腿骨頸部骨折は高齢者の転倒で多発し（寝たきりの主要原因）、早期手術が推奨される。大腿骨頭への血流は関節包内骨折で障害されやすい。", example:"Femoral neck fracture in the elderly patient was treated with hemiarthroplasty within 24 hours.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Patella", de:"Kniescheibe", abbr:"", ja:"膝蓋骨", note:"膝関節前面の種子骨。大腿四頭筋腱・膝蓋靱帯の連結部。転倒・打撲で骨折。膝蓋骨骨折は膝伸展障害を来す。", example:"Patella fracture with extensor mechanism disruption required tension band wiring.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Tibia", de:"Schienbein", abbr:"", ja:"脛骨", note:"下腿の主要な荷重骨。近位（膝関節）・遠位（足関節）に関節を持つ。脛骨骨幹部骨折は開放骨折になりやすく感染リスクが高い。コンパートメント症候群に注意。", example:"Tibia shaft fracture was stabilized with an intramedullary nail after fasciotomy.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Fibula", de:"Wadenbein", abbr:"", ja:"腓骨", note:"下腿外側の細長い骨。荷重は少ないが足関節の安定に重要。腓骨骨折は足関節骨折に合併することが多い。腓骨頭部では腓骨神経麻痺に注意。", example:"Fibula fracture at the lateral malleolus was treated with plate and screw fixation.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Calcaneus", de:"Fersenbein", abbr:"", ja:"踵骨", note:"足根骨最大の骨。高所からの転落（両踵骨骨折→腰椎骨折を合併することが多い）。関節内骨折ではBöhler角の減少が特徴的。", example:"Calcaneus fracture from a fall was assessed by measuring the Böhler angle on lateral X-ray.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Talus", de:"Sprungbein", abbr:"", ja:"距骨", note:"踵骨・脛骨・腓骨と関節を形成する足根骨。血流が乏しく骨折（距骨頸部骨折）では無腐性壊死（AVN）リスクが高い。", example:"Talus neck fracture was treated urgently to reduce the risk of avascular necrosis.", cat:"anatomy", level:"advanced", dept:"GEN" },

// ── 解剖学：筋肉 ──────────────────────────────────────────────────────
{ en:"Deltoid muscle", de:"Deltamuskel", abbr:"", ja:"三角筋", note:"肩関節を覆う三角形の筋肉。前部（屈曲）・中部（外転）・後部（伸展）の3部から成る。腋窩神経支配。筋肉注射の代表的な部位。", example:"Deltoid muscle atrophy was noted following axillary nerve injury.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Rotator cuff", de:"Rotatorenmanschette", abbr:"RTC", ja:"腱板（ローテーターカフ）", note:"肩関節を安定させる4筋（棘上筋・棘下筋・小円筋・肩甲下筋）の総称。棘上筋腱の断裂が最多。50歳以上で加齢性断裂が増加。", example:"Rotator cuff tear of the supraspinatus was confirmed by MRI and repaired arthroscopically.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Supraspinatus", de:"Musculus supraspinatus", abbr:"", ja:"棘上筋", note:"腱板の主要構成筋。肩関節の外転0〜15度に関与。肩甲上神経支配。腱板断裂の80〜90%を占める。インピンジメント症候群の原因。", example:"Supraspinatus full-thickness tear was repaired with double-row anchor fixation.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Biceps brachii", de:"Musculus biceps brachii", abbr:"", ja:"上腕二頭筋", note:"上腕前面の主要な屈筋。長頭（肩関節内）・短頭（烏口突起）の2頭を持つ。前腕の回外に強く働く。筋皮神経支配。長頭腱断裂（ポパイサイン）が多い。", example:"Biceps brachii long head tendon rupture presented as a Popeye deformity.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Quadriceps femoris", de:"Musculus quadriceps femoris", abbr:"", ja:"大腿四頭筋", note:"大腿前面の最大筋群（大腿直筋・内側広筋・外側広筋・中間広筋の4筋）。膝関節伸展・股関節屈曲に関与。大腿神経支配。膝伸展の主力筋。", example:"Quadriceps femoris strength was assessed at 4/5 on manual muscle testing after knee surgery.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Hamstrings", de:"Ischiokrurale Muskulatur", abbr:"", ja:"ハムストリングス", note:"大腿後面の筋群（大腿二頭筋・半腱様筋・半膜様筋）。膝関節屈曲・股関節伸展に関与。坐骨神経支配。スポーツ肉離れの好発筋。", example:"Hamstrings strain was graded as type II with partial tear on MRI.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Gastrocnemius", de:"Musculus gastrocnemius", abbr:"", ja:"腓腹筋", note:"下腿後面の二頭筋。足関節底屈の主力筋。内側頭・外側頭が合流してアキレス腱を形成。脛骨神経支配。深部静脈血栓症の好発部位。", example:"Gastrocnemius strain caused acute calf pain during sprinting.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Iliopsoas", de:"Musculus iliopsoas", abbr:"", ja:"腸腰筋", note:"腸骨筋と大腰筋から成る股関節屈曲の主力筋。腰椎→小転子に付着。大腿神経支配。腸腰筋血腫は抗凝固療法の合併症として重要。", example:"Iliopsoas hematoma secondary to anticoagulation caused femoral nerve palsy.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Gluteus maximus", de:"Musculus gluteus maximus", abbr:"", ja:"大殿筋", note:"殿部最大の筋肉。股関節伸展・外旋の主力筋。下殿神経支配。筋肉注射の安全部位（外上1/4）として重要。長期臥床で萎縮しやすい。", example:"Gluteus maximus atrophy was evident after prolonged immobilization.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Diaphragm", de:"Zwerchfell", abbr:"", ja:"横隔膜", note:"胸腔と腹腔を分ける主要な呼吸筋。収縮で胸腔が拡大し吸気が生じる。横隔神経（C3-C5）支配。大動脈裂孔・食道裂孔・大静脈裂孔の3孔を持つ。", example:"Diaphragm paralysis due to phrenic nerve injury caused dyspnea and elevated hemidiaphragm.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Intercostal muscles", de:"Zwischenrippenmuskeln", abbr:"", ja:"肋間筋", note:"肋骨間の外肋間筋（吸気補助）・内肋間筋（呼気補助）・最内肋間筋から成る。肋間神経・動静脈の走行。肋間神経ブロックの解剖学的基礎。", example:"Intercostal nerve block was performed at the lower rib angle for post-thoracotomy pain.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Rectus abdominis", de:"Musculus rectus abdominis", abbr:"", ja:"腹直筋", note:"腹部正中の縦走筋。腹腔内圧の上昇・体幹屈曲に関与。鼠径部手術・帝王切開の切開創に近接。腹直筋鞘血腫は抗凝固療法で生じる。", example:"Rectus abdominis hematoma caused acute abdominal pain in the anticoagulated patient.", cat:"anatomy", level:"basic", dept:"GEN" },

// ── 解剖学：神経 ──────────────────────────────────────────────────────
{ en:"Olfactory nerve (CN I)", de:"Riechnerv (N. olfactorius)", abbr:"CN I", ja:"嗅神経（第1脳神経）", note:"嗅覚を伝える感覚神経。篩板を通り嗅球へ入力する。頭蓋底骨折・前頭葉腫瘍・パーキンソン病の初期症状として嗅覚脱失が生じる。", example:"Olfactory nerve function was lost after ethmoid bone fracture, causing anosmia.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Optic nerve (CN II)", de:"Sehnerv (N. opticus)", abbr:"CN II", ja:"視神経（第2脳神経）", note:"視覚を伝える感覚神経。視交叉で半側交叉し視索へ続く。視交叉での圧迫（下垂体腫瘍）で両耳側半盲を来す。乳頭浮腫は頭蓋内圧亢進の所見。", example:"Optic nerve compression by a pituitary adenoma caused bitemporal hemianopia.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Facial nerve (CN VII)", de:"Gesichtsnerv (N. facialis)", abbr:"CN VII", ja:"顔面神経（第7脳神経）", note:"顔面筋の運動を支配し・鼓索神経で舌前2/3の味覚・顎下腺・舌下腺の分泌も担う。ベル麻痺・帯状疱疹（ラムゼイハント症候群）・耳下腺腫瘍で障害される。", example:"Facial nerve palsy was graded House-Brackmann IV after acoustic neuroma surgery.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Vagus nerve (CN X)", de:"Vagusnerv (N. vagus)", abbr:"CN X", ja:"迷走神経（第10脳神経）", note:"副交感神経の主要神経。咽喉・胸腹部臓器（心臓・肺・消化管）を支配する最長の脳神経。反回喉頭神経は声帯を支配し、甲状腺手術・胸部大動脈瘤で障害リスク。", example:"Vagus nerve injury during thyroidectomy caused hoarseness due to recurrent laryngeal nerve palsy.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Radial nerve", de:"Speichennerv", abbr:"", ja:"橈骨神経", note:"腕神経叢後索から起始（C5-T1）。上腕骨橈骨神経溝を走行。手関節・指の伸展を支配。上腕骨骨幹部骨折・松葉杖使用で障害→「下垂手（drop wrist）」。", example:"Radial nerve palsy causing wrist drop was confirmed by nerve conduction study.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Median nerve", de:"Mittelnerv", abbr:"", ja:"正中神経", note:"腕神経叢内側・外側索から起始（C6-T1）。前腕屈筋・手の母指球筋を支配。手根管症候群（手根管での圧迫）が最多絞扼性神経障害。母指・示指・中指の感覚障害。", example:"Median nerve entrapment at the carpal tunnel caused nocturnal paresthesia in the first three fingers.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Ulnar nerve", de:"Ellennerv", abbr:"", ja:"尺骨神経", note:"腕神経叢内側索から起始（C8-T1）。肘部管（肘頭内側）・ギオン管（手根部）での絞扼が多い。手内在筋・小指球筋を支配。「鷲手変形」が麻痺の特徴。", example:"Ulnar nerve neuropathy at the elbow caused weakness and sensory loss in the ring and little fingers.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Sciatic nerve", de:"Ischiasnerv", abbr:"", ja:"坐骨神経", note:"人体最大の末梢神経。L4-S3から起始。大坐骨孔→梨状筋下→大腿後面を走行し膝窩で腓骨神経・脛骨神経に分岐。梨状筋症候群・股関節手術で障害リスク。", example:"Sciatic nerve injury during hip arthroplasty caused footdrop and sensory loss in the leg.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Femoral nerve", de:"Oberschenkelnerv", abbr:"", ja:"大腿神経", note:"腰神経叢（L2-L4）から起始。鼠径靱帯下を通り大腿前面へ。大腿四頭筋・縫工筋の運動・大腿前面・下腿内側の感覚を担う。腸腰筋血腫で障害リスク。", example:"Femoral nerve block provided effective analgesia after total knee replacement.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Common peroneal nerve", de:"Nervus fibularis communis", abbr:"", ja:"総腓骨神経", note:"坐骨神経の分枝（L4-S2）。腓骨頭を回り浅深腓骨神経に分岐。下垂足・足背・下腿外側の感覚障害を来す。腓骨頸部骨折・石膏ギプスによる圧迫で障害しやすい。", example:"Common peroneal nerve palsy from fibular head compression caused footdrop.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Cauda equina", de:"Cauda equina", abbr:"", ja:"馬尾", note:"脊髄円錐（L1-L2レベル）以下の腰仙髄神経根の束。「馬の尾」に似た外観。馬尾症候群（腰部脊柱管狭窄・ヘルニア）では膀胱直腸障害・下肢弛緩性麻痺を来す。", example:"Cauda equina syndrome with urinary retention required emergency surgical decompression.", cat:"anatomy", level:"advanced", dept:"GEN" },
{ en:"Brachial plexus", de:"Armgeflecht", abbr:"", ja:"腕神経叢", note:"C5〜T1の神経根から形成される神経網。根→幹→索→末梢神経へ。出生時麻痺（エルブ麻痺・クルンプケ麻痺）・外傷（バイク事故）・胸郭出口症候群で障害される。", example:"Brachial plexus injury following motorcycle accident caused flail arm and Horner's syndrome.", cat:"anatomy", level:"advanced", dept:"GEN" },

// ── 解剖学：靱帯・腱 ─────────────────────────────────────────────────
{ en:"Anterior cruciate ligament", de:"Vorderes Kreuzband", abbr:"ACL", ja:"前十字靱帯", note:"膝関節の主要安定靱帯。脛骨の前方移動・内旋を制御。スポーツ中の非接触型機序（着地・方向転換）で断裂が多い。MRIで診断。再建術が標準治療。", example:"ACL rupture was confirmed by positive Lachman test and MRI, treated with patellar tendon graft.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Posterior cruciate ligament", de:"Hinteres Kreuzband", abbr:"PCL", ja:"後十字靱帯", note:"脛骨の後方移動を制御する膝関節の靱帯。前十字靱帯より太く強固。ダッシュボード損傷（膝屈曲位への前方衝撃）で断裂。後方引き出しテストが有用。", example:"PCL injury was identified by posterior drawer test and confirmed on MRI.", cat:"anatomy", level:"intermediate", dept:"GEN" },
{ en:"Medial collateral ligament", de:"Mediales Seitenband", abbr:"MCL", ja:"内側側副靱帯", note:"膝関節内側の安定を担う靱帯。外反ストレスで損傷。ACL断裂と合併することが多い。Grade I・IIは保存療法、Grade IIIは手術を考慮。", example:"MCL sprain grade II was treated with knee brace and physiotherapy.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Achilles tendon", de:"Achillessehne", abbr:"", ja:"アキレス腱", note:"腓腹筋・ヒラメ筋の腱が合流した人体最強の腱。踵骨後面に付着。断裂はスポーツ中の突然の蹴り出し動作で生じる。トンプソンテスト陽性。", example:"Achilles tendon rupture was treated with functional bracing in equinus position.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Plantar fascia", de:"Plantarfaszie", abbr:"", ja:"足底腱膜", note:"踵骨から趾骨基部に扇状に広がる線維性組織。足のアーチを保持する。踵骨棘・過負荷でplantar fasciitis（足底腱膜炎）を来す。朝の第一歩の踵痛が特徴。", example:"Plantar fasciitis was managed with stretching, orthotics, and shockwave therapy.", cat:"anatomy", level:"basic", dept:"GEN" },
{ en:"Rotator interval", de:"Rotatorenintervall", abbr:"", ja:"腱板疎部（ローテーターインターバル）", note:"棘上筋腱と肩甲下筋腱の間の三角形の間隙。烏口上腕靱帯・上関節上腕靱帯が走行。凍結肩（拘縮肩）では腱板疎部の瘢痕化・拘縮が生じる。", example:"Rotator interval contracture was released arthroscopically for refractory frozen shoulder.", cat:"anatomy", level:"advanced", dept:"GEN" },
];
